      const newLogs = [entry, ...prev];
      if (newLogs.length > MAX_LOG_HISTORY) {
        // Explicitly release memory of dropped items if they were ObjectURLs (here they are base64 strings)
        return newLogs.slice(0, MAX_LOG_HISTORY);
