import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

// Schema for structured JSON output
const analysisSchema = {
  type: Type.OBJECT,
  properties: {
    safetyScore: { type: Type.NUMBER, description: "Safety score 0-100" },
    isSafe: { type: Type.BOOLEAN },
    summary: { type: Type.STRING, description: "Brief summary in Persian" },
    hazards: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          type: { type: Type.STRING },
          severity: { type: Type.STRING, enum: ["HIGH", "MEDIUM", "LOW", "SAFE"] },
          description: { type: Type.STRING, description: "Description in Persian" },
          recommendation: { type: Type.STRING, description: "Actionable advice in Persian" },
          bbox: { type: Type.ARRAY, items: { type: Type.NUMBER }, description: "[ymin, xmin, ymax, xmax] normalized to 1000" }
        },
        required: ["type", "severity", "description", "recommendation"]
      }
    }
  },
  required: ["safetyScore", "isSafe", "summary", "hazards"]
};

export const analyzeImage = async (base64Image: string): Promise<AnalysisResult> => {
  try {
    if (!process.env.API_KEY) throw new Error("API Key missing");

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Using gemini-2.5-flash for speed
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: {
        parts: [
          { inlineData: { mimeType: "image/jpeg", data: base64Image } },
          { text: "Analyze this industrial scene for safety hazards (PPE, Fire, Machinery). Return JSON." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: analysisSchema
      }
    });

    if (response.text) {
      const data = JSON.parse(response.text);
      return {
        id: Date.now().toString(),
        timestamp: new Date().toLocaleTimeString('fa-IR'),
        ...data,
        image: base64Image // Store mainly for thumbnail display
      };
    }
    throw new Error("No response text");
  } catch (error) {
    console.error("Analysis Failed:", error);
    // Return a fallback error object so the UI doesn't crash
    return {
      id: Date.now().toString(),
      timestamp: new Date().toLocaleTimeString(),
      safetyScore: 0,
      isSafe: false,
      summary: "خطا در ارتباط با هوش مصنوعی",
      hazards: []
    };
  }
};

