    try {
      // Remove data:image/jpeg;base64, prefix
      const base64 = imageSrc.split(',')[1];
      const result = await analyzeImage(base64);
      setLastResult(result);
      onResult(result);
    } catch (e) {
      console.error(e);
    } finally {
      setIsProcessing(false);
    }
  }, [isProcessing, onResult]);

