import { GoogleGenAI, LiveServerMessage, Modality } from "@google/genai";

export default function VoiceAssistant() {
  const [connected, setConnected] = useState(false);
  const [status, setStatus] = useState("Ready to Connect");

  // Audio Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const nextStartTimeRef = useRef<number>(0);

  const disconnect = () => {
    if (processorRef.current) {
      processorRef.current.disconnect();
      processorRef.current = null;
    }
    if (sourceRef.current) {
      sourceRef.current.disconnect();
      sourceRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(t => t.stop());
      streamRef.current = null;
    }
    if (audioContextRef.current) {
      audioContextRef.current.close();
      audioContextRef.current = null;
    }
    setConnected(false);
    setStatus("Disconnected");
  };

  const connect = async () => {
    setStatus("Initializing Audio...");
    try {
      if (!process.env.API_KEY) throw new Error("Missing API Key");

      // 1. Setup Audio Context (Output)
      const AudioCtx = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioCtx({ sampleRate: 24000 });
      audioContextRef.current = ctx;
      nextStartTimeRef.current = ctx.currentTime;

      // 2. Setup Mic (Input)
      const stream = await navigator.mediaDevices.getUserMedia({
        audio: {
          sampleRate: 16000,
          channelCount: 1,
          echoCancellation: true
        }
      });
      streamRef.current = stream;

      // 3. Setup Gemini
      setStatus("Connecting to AI...");
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } },
          systemInstruction: "You are an HSE safety expert. Keep answers short, professional, and safety-focused."
        },
        callbacks: {
          onopen: () => {
            setConnected(true);
            setStatus("Listening...");
            startAudioStream(ctx, stream, sessionPromise);
          },
          onmessage: async (msg: LiveServerMessage) => {
            if (msg.serverContent?.modelTurn?.parts?.[0]?.inlineData) {
              setStatus("Speaking...");
              playAudio(msg.serverContent.modelTurn.parts[0].inlineData.data, ctx);
            }
            if (msg.serverContent?.turnComplete) {
              setTimeout(() => setStatus("Listening..."), 500);
            }
          },
          onclose: () => disconnect(),
          onerror: (err) => {
            console.error(err);
            setStatus("Error: " + err.message);
            disconnect();
          }
        }
      });

    } catch (e: any) {
      setStatus("Error: " + e.message);
      disconnect();
    }
  };

  const startAudioStream = (ctx: AudioContext, stream: MediaStream, sessionPromise: Promise<any>) => {
    const source = ctx.createMediaStreamSource(stream);
    sourceRef.current = source;

    const processor = ctx.createScriptProcessor(4096, 1, 1);
    processorRef.current = processor;

    processor.onaudioprocess = (e) => {
      const input = e.inputBuffer.getChannelData(0);
      // Simple float to int16 conversion
      const pcm16 = new Int16Array(input.length);
      for (let i = 0; i < input.length; i++) {
        pcm16[i] = input[i] * 0x7FFF;
      }

      // ArrayBuffer to Base64
      let binary = '';
      const bytes = new Uint8Array(pcm16.buffer);
      for (let i = 0; i < bytes.length; i++) binary += String.fromCharCode(bytes[i]);
      const base64 = btoa(binary);

      sessionPromise.then(session => {
        session.sendRealtimeInput({
          media: { mimeType: "audio/pcm;rate=" + ctx.sampleRate, data: base64 }
        });
      });
    };

    source.connect(processor);
    // Connect processor to a muted destination to keep it alive without feedback
    const mute = ctx.createGain();
    mute.gain.value = 0;
    processor.connect(mute);
    mute.connect(ctx.destination);
  };

  const playAudio = (base64: string, ctx: AudioContext) => {
    // Base64 -> ArrayBuffer -> Int16 -> Float32 -> AudioBuffer
    const bin = atob(base64);
    const bytes = new Uint8Array(bin.length);
    for (let i=0; i<bin.length; i++) bytes[i] = bin.charCodeAt(i);
    const int16 = new Int16Array(bytes.buffer);
    const float32 = new Float32Array(int16.length);
    for(let i=0; i<int16.length; i++) float32[i] = int16[i] / 32768.0;

    const buffer = ctx.createBuffer(1, float32.length, 24000);
    buffer.copyToChannel(float32, 0);

    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);

    const now = ctx.currentTime;
    const start = Math.max(now, nextStartTimeRef.current);
    source.start(start);
    nextStartTimeRef.current = start + buffer.duration;
  };

  useEffect(() => {
    return () => disconnect();
  }, []);

  return (
    <div className="flex flex-col items-center justify-center h-full bg-slate-900 text-white relative overflow-hidden">
      {/* Visual Background */}
      <div className={`absolute inset-0 transition-opacity duration-1000 ${connected ? 'opacity-30' : 'opacity-0'}`}>
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-96 h-96 bg-blue-500 rounded-full blur-[100px] animate-pulse"></div>
      </div>

      <div className="z-10 text-center">
        <h2 className="text-3xl font-bold mb-8">HSE AI Voice Assistant</h2>

        <div className="relative mb-12 flex justify-center">
          <button
            onClick={connected ? disconnect : connect}
            className={`w-32 h-32 rounded-full flex items-center justify-center transition-all shadow-2xl ${
              connected 
              ? 'bg-red-500 hover:bg-red-600 shadow-red-500/50' 
              : 'bg-blue-600 hover:bg-blue-500 shadow-blue-500/50'
            }`}
          >
            {connected ? <MicOff className="w-12 h-12" /> : <Mic className="w-12 h-12" />}
          </button>

          {connected && (
            <div className="absolute inset-0 rounded-full border-4 border-white/20 animate-ping pointer-events-none"></div>
          )}
        </div>

        <div className="bg-slate-800/80 backdrop-blur px-6 py-3 rounded-full border border-slate-600 inline-flex items-center gap-3">
          {connected ? <Radio className="w-4 h-4 text-emerald-400 animate-pulse" /> : <Loader2 className="w-4 h-4 text-slate-400" />}
          <span className="font-mono text-sm tracking-widest uppercase">{status}</span>
        </div>
      </div>
    </div>
  );
}

