export const analyzeImage = async (base64Image: string, sensitivity: number = 50): Promise<AnalysisResult> => {
  try {
    if (!process.env.API_KEY) throw new Error("API Key missing");

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Customize prompt based on sensitivity
    const sensitivityContext = sensitivity > 70 
      ? "Be extremely strict. Flag even the slightest PPE non-compliance or minor potential hazards."
      : sensitivity < 30
      ? "Focus only on immediate, life-threatening dangers or major fire hazards. Ignore minor PPE issues."
      : "Standard industrial safety check. Balance between strictness and practical hazard assessment.";

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          { inlineData: { mimeType: "image/jpeg", data: base64Image } },
          { text: `Analyze this industrial scene. Sensitivity level is ${sensitivity}/100. ${sensitivityContext} Return results in JSON.` }
        ]
      },
      config: {
        systemInstruction: "You are a senior HSE (Health, Safety, and Environment) officer. Your analysis must be precise and context-aware. Use Persian for all descriptive text.",
        responseMimeType: "application/json",
        responseSchema: analysisSchema
      }
    });

    if (response.text) {
      const data = JSON.parse(response.text);
      return {
        id: Date.now().toString(),
        timestamp: new Date().toLocaleTimeString('fa-IR'),
        ...data,
        image: base64Image
      };
    }
    throw new Error("No response text");
  } catch (error) {
    console.error("Analysis Failed:", error);
    return {
      id: Date.now().toString(),
      timestamp: new Date().toLocaleTimeString(),
      safetyScore: 0,
      isSafe: false,
      summary: "خطا در تحلیل هوشمند تصویر",
      hazards: []
    };
  }
};

import React, { useRef, useState, useEffect, useCallback } from 'react';
import Webcam from 'react-webcam';
import { Camera, AlertTriangle, ShieldCheck, Activity, Play, Pause, Bell, BellOff, Sliders } from 'lucide-react';
import { analyzeImage } from '../services/geminiService';
import { AnalysisResult } from '../types';

interface MonitorProps {
  onResult: (result: AnalysisResult) => void;
}

export default function Monitor({ onResult }: MonitorProps) {
  const webcamRef = useRef<Webcam>(null);
  const audioContextRef = useRef<AudioContext | null>(null);

  const [isActive, setIsActive] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [lastResult, setLastResult] = useState<AnalysisResult | null>(null);
  const [sensitivity, setSensitivity] = useState(50);
  const [isAlarming, setIsAlarming] = useState(false);
  const [isAlarmSilenced, setIsAlarmSilenced] = useState(false);

  // Initialize Audio Context for industrial beep
  const initAudio = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
  };

  const playAlarmSound = useCallback(() => {
    if (!audioContextRef.current || isAlarmSilenced) return;

    const ctx = audioContextRef.current;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(880, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(440, ctx.currentTime + 0.5);

    gain.gain.setValueAtTime(0.1, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.5);

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start();
    osc.stop(ctx.currentTime + 0.5);
  }, [isAlarmSilenced]);

  const capture = useCallback(async () => {
    if (!webcamRef.current || isProcessing) return;

    const imageSrc = webcamRef.current.getScreenshot();
    if (!imageSrc) return;

    setIsProcessing(true);
    try {
      const base64 = imageSrc.split(',')[1];
      const result = await analyzeImage(base64, sensitivity);
      setLastResult(result);
      onResult(result);

      // Check for HIGH severity hazards to trigger alarm
      const hasHighHazard = result.hazards.some(h => h.severity === 'HIGH');
      if (hasHighHazard) {
        setIsAlarming(true);
        // Only auto-play if not manually silenced for this session
        if (!isAlarmSilenced) playAlarmSound();
      } else {
        setIsAlarming(false);
        setIsAlarmSilenced(false); // Reset silence when safe
      }

    } catch (e) {
      console.error(e);
    } finally {
      setIsProcessing(false);
    }
  }, [isProcessing, onResult, sensitivity, isAlarmSilenced, playAlarmSound]);

  useEffect(() => {
    let interval: any;
    if (isActive) {
      interval = setInterval(capture, 3000);
    }
    return () => clearInterval(interval);
  }, [isActive, capture]);

  const toggleMonitor = () => {
    initAudio();
    setIsActive(!isActive);
  };

  const silenceAlarm = () => {
    setIsAlarmSilenced(true);
    setIsAlarming(false);
  };

  return (
    <div className="flex flex-col h-full gap-4">
      {/* Top Controls Bar */}
      <div className="flex flex-wrap items-center justify-between bg-slate-800 p-4 rounded-xl border border-slate-700 gap-4">
        <div className="flex items-center gap-3">
          <div className={`p-2 rounded-full ${isActive ? 'bg-red-500/20 text-red-500 animate-pulse' : 'bg-slate-700 text-slate-400'}`}>
            <Camera className="w-6 h-6" />
          </div>
          <div>
            <h2 className="font-bold text-white">مانیتورینگ هوشمند</h2>
            <p className="text-xs text-slate-400">{isActive ? "درحال پایش محیط" : "آماده به کار"}</p>
          </div>
        </div>

        {/* Sensitivity Controller */}
        <div className="flex items-center gap-4 bg-slate-900/50 px-4 py-2 rounded-lg border border-slate-700">
          <Sliders className="w-4 h-4 text-slate-400" />
          <div className="flex flex-col">
            <label className="text-[10px] text-slate-500 font-bold uppercase mb-1">حساسیت تشخیص: {sensitivity}%</label>
            <input 
              type="range" 
              min="10" 
              max="100" 
              value={sensitivity} 
              onChange={(e) => setSensitivity(parseInt(e.target.value))}
              className="w-32 h-1 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-orange-500"
            />
          </div>
        </div>

        <div className="flex items-center gap-3">
          {isAlarming && (
            <button
              onClick={silenceAlarm}
              className="flex items-center gap-2 px-4 py-2 bg-amber-600 hover:bg-amber-500 text-white rounded-lg font-bold text-sm transition-all animate-bounce"
            >
              <BellOff className="w-4 h-4" />
              قطع موقت آلارم
            </button>
          )}
          <button
            onClick={toggleMonitor}
            className={`flex items-center gap-2 px-6 py-2 rounded-lg font-bold transition-all ${
              isActive ? 'bg-red-600 hover:bg-red-700 text-white' : 'bg-emerald-600 hover:bg-emerald-500 text-white'
            }`}
          >
