import React, { useRef, useState, useEffect, useCallback } from 'react';
import Webcam from 'react-webcam';
import { Camera, AlertTriangle, ShieldCheck, Activity, Play, Pause, Bell, BellOff, Sliders, Timer } from 'lucide-react';
import { analyzeImage } from '../services/geminiService';
import { AnalysisResult } from '../types';

interface MonitorProps {
  onResult: (result: AnalysisResult) => void;
}

export default function Monitor({ onResult }: MonitorProps) {
  const webcamRef = useRef<Webcam>(null);
  const audioContextRef = useRef<AudioContext | null>(null);

  const [isActive, setIsActive] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [lastResult, setLastResult] = useState<AnalysisResult | null>(null);
  const [sensitivity, setSensitivity] = useState(50);
  const [isAlarming, setIsAlarming] = useState(false);
  const [isAlarmSilenced, setIsAlarmSilenced] = useState(false);
  const [snoozeUntil, setSnoozeUntil] = useState<number | null>(null);

  // Initialize Audio Context for industrial beep
  const initAudio = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
  };

  const playAlarmSound = useCallback(() => {
    const isSnoozed = snoozeUntil ? Date.now() < snoozeUntil : false;
    if (!audioContextRef.current || isAlarmSilenced || isSnoozed) return;

    const ctx = audioContextRef.current;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(880, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(440, ctx.currentTime + 0.5);

    gain.gain.setValueAtTime(0.1, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.5);

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start();
    osc.stop(ctx.currentTime + 0.5);
  }, [isAlarmSilenced, snoozeUntil]);

  const capture = useCallback(async () => {
    if (!webcamRef.current || isProcessing) return;

    const imageSrc = webcamRef.current.getScreenshot();
    if (!imageSrc) return;

    setIsProcessing(true);
    try {
      const base64 = imageSrc.split(',')[1];
      const result = await analyzeImage(base64, sensitivity);
      setLastResult(result);
      onResult(result);

      // Check for HIGH severity hazards to trigger alarm
      const hasHighHazard = result.hazards.some(h => h.severity === 'HIGH');
      const isSnoozed = snoozeUntil ? Date.now() < snoozeUntil : false;

      if (hasHighHazard) {
        if (!isSnoozed && !isAlarmSilenced) {
          setIsAlarming(true);
          playAlarmSound();
        } else {
          setIsAlarming(false); // Visually calm but hazard still recorded
        }
      } else {
        setIsAlarming(false);
        setIsAlarmSilenced(false); // Reset silence when environment returns to safe
        setSnoozeUntil(null); // Clear snooze when safe
      }

    } catch (e) {
      console.error(e);
    } finally {
      setIsProcessing(false);
    }
  }, [isProcessing, onResult, sensitivity, isAlarmSilenced, snoozeUntil, playAlarmSound]);

  useEffect(() => {
    let interval: any;
    if (isActive) {
      interval = setInterval(capture, 3000);
    }
    return () => clearInterval(interval);
  }, [isActive, capture]);

  const toggleMonitor = () => {
    initAudio();
    setIsActive(!isActive);
  };

  const silenceAlarm = () => {
    setIsAlarmSilenced(true);
    setIsAlarming(false);
  };

  const snoozeAlarm = (minutes: number) => {
    const until = Date.now() + (minutes * 60 * 1000);
    setSnoozeUntil(until);
    setIsAlarming(false);
  };

  return (
    <div className="flex flex-col h-full gap-4">
      {/* Top Controls Bar */}
      <div className="flex flex-wrap items-center justify-between bg-slate-800 p-4 rounded-xl border border-slate-700 gap-4">
        <div className="flex items-center gap-3">
          <div className={`p-2 rounded-full ${isActive ? 'bg-red-500/20 text-red-500 animate-pulse' : 'bg-slate-700 text-slate-400'}`}>
            <Camera className="w-6 h-6" />
          </div>
          <div>
            <h2 className="font-bold text-white">مانیتورینگ هوشمند</h2>
            <p className="text-xs text-slate-400">{isActive ? "درحال پایش محیط" : "آماده به کار"}</p>
          </div>
        </div>

        {/* Sensitivity Controller */}
        <div className="flex items-center gap-4 bg-slate-900/50 px-4 py-2 rounded-lg border border-slate-700">
          <Sliders className="w-4 h-4 text-slate-400" />
          <div className="flex flex-col">
            <label className="text-[10px] text-slate-500 font-bold uppercase mb-1">حساسیت تشخیص: {sensitivity}%</label>
            <input 
              type="range" 
              min="10" 
              max="100" 
              value={sensitivity} 
              onChange={(e) => setSensitivity(parseInt(e.target.value))}
              className="w-32 h-1 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-orange-500"
            />
          </div>
        </div>

        <div className="flex items-center gap-2">
          {isAlarming && (
            <>
              <button
                onClick={() => snoozeAlarm(5)}
                className="flex items-center gap-2 px-3 py-2 bg-slate-700 hover:bg-slate-600 text-white rounded-lg font-bold text-xs transition-all border border-slate-600"
                title="Snooze for 5 minutes"
              >
                <Timer className="w-4 h-4 text-orange-400" />
                Snooze 5m
              </button>
              <button
                onClick={silenceAlarm}
                className="flex items-center gap-2 px-4 py-2 bg-amber-600 hover:bg-amber-500 text-white rounded-lg font-bold text-sm transition-all animate-bounce shadow-lg shadow-amber-900/40"
              >
                <BellOff className="w-4 h-4" />
                قطع آلارم
              </button>
            </>
          )}
          <button
            onClick={toggleMonitor}
            className={`flex items-center gap-2 px-6 py-2 rounded-lg font-bold transition-all shadow-lg ${
              isActive 
                ? 'bg-red-600 hover:bg-red-700 text-white shadow-red-900/40' 
                : 'bg-emerald-600 hover:bg-emerald-500 text-white shadow-emerald-900/40'
            }`}
          >
            {isActive ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />}
            {isActive ? "توقف پایش" : "شروع پایش"}
          </button>
        </div>
      </div>

      <div className="flex flex-col lg:flex-row gap-4 h-full overflow-hidden">
        {/* Camera Feed Area */}
        <div className={`flex-1 bg-black rounded-xl border-2 transition-colors duration-500 relative overflow-hidden flex items-center justify-center ${isAlarming ? 'border-red-500 alarm-active' : 'border-slate-700'}`}>
          <Webcam
            ref={webcamRef}
            screenshotFormat="image/jpeg"
            className="w-full h-full object-contain"
            videoConstraints={{ width: 1280, height: 720, facingMode: "environment" }}
          />

          {/* Overlay for detections */}
          {lastResult && lastResult.hazards.map((h, i) => {
            if (!h.bbox) return null;
            const [ymin, xmin, ymax, xmax] = h.bbox;
            const isHigh = h.severity === 'HIGH';
            return (
              <div
                key={i}
                className={`absolute border-2 z-10 flex items-start justify-center ${isHigh ? 'border-red-500 bg-red-500/10' : 'border-amber-400 bg-amber-400/10'}`}
                style={{
                  top: `${ymin / 10}%`,
                  left: `${xmin / 10}%`,
                  height: `${(ymax - ymin) / 10}%`,
                  width: `${(xmax - xmin) / 10}%`,
                }}
              >
                <span className={`text-[10px] font-bold px-1 rounded -mt-4 text-white ${isHigh ? 'bg-red-600' : 'bg-amber-500'}`}>
                  {h.type}
                </span>
              </div>
            );
          })}

          {isProcessing && (
            <div className="absolute top-4 right-4 bg-blue-600 text-white px-4 py-1.5 rounded-full text-xs font-bold animate-pulse shadow-lg flex items-center gap-2 z-20">
              <Activity className="w-3 h-3" />
              تحلیل هوشمند...
            </div>
          )}

          {isAlarming && (
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-20">
              <div className="bg-red-600/90 text-white px-8 py-4 rounded-2xl flex flex-col items-center gap-2 shadow-2xl border-4 border-red-400 animate-pulse">
                <AlertTriangle className="w-12 h-12" />
                <span className="text-xl font-black tracking-widest rtl-font">وضعیت خطرناک شناسایی شد</span>
              </div>
            </div>
          )}

          {snoozeUntil && Date.now() < snoozeUntil && (
            <div className="absolute bottom-4 left-4 bg-slate-800/90 text-slate-300 px-3 py-1 rounded-full text-[10px] font-bold border border-slate-600 flex items-center gap-2 z-20">
              <Timer className="w-3 h-3 text-orange-400" />
              آلارم موقتاً غیرفعال است (Snoozed)
            </div>
          )}
        </div>

        {/* Results Side Panel */}
        <div className="w-full lg:w-96 bg-slate-800 rounded-xl border border-slate-700 flex flex-col overflow-hidden">
          <div className="p-4 border-b border-slate-700 bg-slate-900/50 flex justify-between items-center">
            <h3 className="font-bold text-slate-200">گزارش لحظه‌ای</h3>
            <div className="flex gap-2">
              <div className={`w-2 h-2 rounded-full ${isActive ? 'bg-emerald-500' : 'bg-slate-600'}`}></div>
            </div>
          </div>

          {!lastResult ? (
            <div className="flex-1 flex flex-col items-center justify-center text-slate-500 p-8 text-center">
              <ShieldCheck className="w-12 h-12 mb-4 opacity-20" />
              <p className="text-sm">برای شروع تحلیل، دکمه شروع پایش را بزنید.</p>
            </div>
          ) : (
            <div className="flex-1 overflow-y-auto p-4 space-y-4 rtl-font text-right">
              {/* Score Display */}
              <div className="bg-slate-900/50 p-4 rounded-xl border border-slate-700 flex justify-between items-center">
                <div className={`text-3xl font-black ${lastResult.safetyScore > 80 ? 'text-emerald-400' : lastResult.safetyScore > 50 ? 'text-amber-400' : 'text-red-500'}`}>
                  {lastResult.safetyScore}%
                </div>
                <div className="text-right">
                  <div className="text-xs text-slate-500 font-bold uppercase">امتیاز ایمنی کل</div>
