import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { Shield, Play, Pause, Grid, Maximize2, AlertTriangle, Activity, CheckCircle2, FileText, X, Loader2, Settings2 } from 'lucide-react';
import { GoogleGenAI } from "@google/genai";
import { CameraGrid } from './components/CameraGrid';
import { Pagination } from './components/Pagination';
import { SingleCameraView } from './components/SingleCameraView';
import { AuthGuard } from './components/AuthGuard';
import { CameraSetupModal } from './components/CameraSetupModal';
import { Detection, CameraDevice, SafetyScore } from './types';
import { performanceMonitor } from './utils/performanceMonitor';

// Constants
const MAX_LOGS = 100;
const FRAME_SKIP = 10;
const CAMERA_WIDTH = 320;
const CAMERA_HEIGHT = 240;
const MAX_SIMULTANEOUS_STREAMS = 9;
const CAMERAS_PER_PAGE = 9;

export default function HSEGuardianAI() {
  // State
  const [cameras, setCameras] = useState<CameraDevice[]>(() => 
    Array.from({ length: 9 }, (_, i) => ({
      id: `cam${i + 1}`,
      name: `Simulated Unit ${i + 1}`,
      location: `Zone ${Math.floor(i / 10) + 1} - Sec ${(i % 10) + 1}`,
      active: false,
      riskScore: 0,
      fps: 0,
      status: 'offline' as const,
      connectionType: 'simulation' as const
    }))
  );

  const [detections, setDetections] = useState<Detection[]>([]);
  const [safetyScore, setSafetyScore] = useState<SafetyScore>({
    overall: 98,
    ppe: 99,
    behavior: 95,
    environment: 98
  });

  const [selectedCameraId, setSelectedCameraId] = useState<string>('cam1');
  const [currentPage, setCurrentPage] = useState(0);
  const [viewMode, setViewMode] = useState<'grid' | 'single'>('grid');
  const [filterRisk, setFilterRisk] = useState<'all' | 'high'>('all');

  // Report State
  const [isReportOpen, setIsReportOpen] = useState(false);
  const [reportContent, setReportContent] = useState("");
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);

  // Config Modal State
  const [isConfigOpen, setIsConfigOpen] = useState(false);

  // Performance State
  const [perfMetrics, setPerfMetrics] = useState({ 
    fps: 0, 
    memory: 0, 
    status: 'healthy' as 'healthy' | 'warning' | 'critical' 
  });

  // Refs for processing
  const videoRefs = useRef<Map<string, HTMLVideoElement>>(new Map());
  const canvasRefs = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const frameCountRef = useRef(0);
  const processingQueueRef = useRef<string[]>([]);

  // Helpers
  const addDetection = useCallback((detection: Detection) => {
    setDetections(prev => {
      const updated = [detection, ...prev];
      return updated.slice(0, MAX_LOGS);
    });
  }, []);

  // Performance Monitor Integration
  useEffect(() => {
    performanceMonitor.start();

    const interval = setInterval(() => {
      const metrics = performanceMonitor.getCurrentMetrics();
      const health = performanceMonitor.getHealthStatus();

      if (metrics) {
        setPerfMetrics({
          fps: metrics.fps,
          memory: metrics.memoryUsage,
          status: health.status
        });
      }
    }, 1000);

    return () => {
      performanceMonitor.stop();
      clearInterval(interval);
    };
  }, []);

  // Pagination Logic
  const filteredCameras = useMemo(() => {
    if (filterRisk === 'all') return cameras;
    return cameras.filter(cam => cam.riskScore > 30);
  }, [cameras, filterRisk]);

  const totalPages = Math.ceil(filteredCameras.length / CAMERAS_PER_PAGE);

  const visibleCameras = useMemo(() => {
    const start = currentPage * CAMERAS_PER_PAGE;
    return filteredCameras.slice(start, start + CAMERAS_PER_PAGE);
  }, [filteredCameras, currentPage]);

  const activeCamera = useMemo(() => 
    cameras.find(c => c.id === selectedCameraId) || cameras[0]
  , [cameras, selectedCameraId]);

  // Update Processing Queue
  const updateProcessingQueue = useCallback(() => {
    const sorted = [...cameras]
      .filter(c => c.active)
      .sort((a, b) => b.riskScore - a.riskScore)
      .slice(0, MAX_SIMULTANEOUS_STREAMS)
      .map(c => c.id);

    processingQueueRef.current = sorted;
  }, [cameras]);

  useEffect(() => {
    updateProcessingQueue();
  }, [cameras, updateProcessingQueue]);

  // Camera Control
  const startCamera = useCallback(async (cameraId: string) => {
    try {
      const camera = cameras.find(c => c.id === cameraId);
      if (!camera) return;

      const activeCount = cameras.filter(c => c.active).length;
      if (activeCount >= MAX_SIMULTANEOUS_STREAMS) {
        return;
      }

      // Handle Network Camera (Mock activation)
      if (camera.connectionType === 'network') {
        setCameras(prev => prev.map(cam => 
            cam.id === cameraId ? { ...cam, active: true, status: 'online' } : cam
        ));
        return;
      }

      // Handle Local Hardware Camera
      const constraints: MediaStreamConstraints = {
        video: {
          width: { ideal: CAMERA_WIDTH },
          height: { ideal: CAMERA_HEIGHT },
          frameRate: { ideal: 15 },
          // CRITICAL FIX: If we have a specific deviceId, use it!
          deviceId: camera.deviceId ? { exact: camera.deviceId } : undefined
        }
      };

      const stream = await navigator.mediaDevices.getUserMedia(constraints);

      setCameras(prev => prev.map(cam => 
        cam.id === cameraId 
          ? { ...cam, active: true, stream, status: 'online' }
          : cam
      ));

      const video = videoRefs.current.get(cameraId);
      if (video) {
        video.srcObject = stream;
        video.play().catch(e => console.error("Play error", e));
      }
    } catch (error: any) {
      console.error('Camera access failed:', error);
      const isNotFoundError = error.name === 'NotFoundError' || error.name === 'DevicesNotFoundError';

      setCameras(prev => prev.map(cam =>
        cam.id === cameraId ? { ...cam, status: isNotFoundError ? 'no-hardware' : 'offline', active: false } : cam
      ));
    }
  }, [cameras]);

  const stopCamera = useCallback((cameraId: string) => {
    setCameras(prev => prev.map(cam => {
      if (cam.id === cameraId && cam.stream) {
        cam.stream.getTracks().forEach(track => track.stop());
        return { ...cam, active: false, stream: undefined, status: 'offline' };
      }
      return cam;
    }));

    const video = videoRefs.current.get(cameraId);
    if (video) video.srcObject = null;
  }, []);

  const handleCameraSelect = (id: string) => {
    setSelectedCameraId(id);
    setViewMode('single');
  };

  const startAllCamerasInPage = useCallback(async () => {
    const promises = visibleCameras
      .filter(c => !c.active && c.status !== 'no-hardware')
      .slice(0, MAX_SIMULTANEOUS_STREAMS)
      .map(c => startCamera(c.id));

    await Promise.allSettled(promises);
  }, [visibleCameras, startCamera]);

  const stopAllCameras = useCallback(() => {
    cameras.filter(c => c.active).forEach(c => stopCamera(c.id));
  }, [cameras, stopCamera]);

  // AI Simulation Loop
  const processFrame = useCallback((cameraId: string) => {
    if (!processingQueueRef.current.includes(cameraId)) return;

    // Only process simulated frames for now as a demo
    const camera = cameras.find(c => c.id === cameraId);
    // Real processing would grab frame from canvas

    frameCountRef.current++;
    if (frameCountRef.current % FRAME_SKIP !== 0) return;

    // Low probability random detection simulation for demo purposes
    if (Math.random() > 0.995) { 
      const violations = [
        { desc: 'Missing Helmet', type: 'ppe', severity: 'medium' },
        { desc: 'Restricted Area', type: 'geofence', severity: 'high' },
        { desc: 'Fall Detected', type: 'fall', severity: 'critical' },
      ] as const;

      const violation = violations[Math.floor(Math.random() * violations.length)];

      const detection: Detection = {
        id: `${cameraId}-${Date.now()}`,
        type: violation.type as any,
        severity: violation.severity as any,
        description: violation.desc,
        timestamp: Date.now(),
        cameraId
      };

      addDetection(detection);

      setCameras(prev => prev.map(cam =>
        cam.id === cameraId
          ? { 
              ...cam, 
              riskScore: Math.min(100, cam.riskScore + (violation.severity === 'critical' ? 30 : 10)), 
              lastDetection: Date.now() 
            }
          : cam
      ));
    }
  }, [addDetection, cameras]);

  // Animation Loop
  useEffect(() => {
    let animationFrame: number;
    const loop = () => {
      processingQueueRef.current.forEach(cameraId => {
        processFrame(cameraId);
      });
      animationFrame = requestAnimationFrame(loop);
    };
    loop();
    return () => cancelAnimationFrame(animationFrame);
  }, [processFrame]);

  // Score Decay (Recovery)
  useEffect(() => {
    const interval = setInterval(() => {
      setCameras(prev => prev.map(cam => ({
        ...cam,
        riskScore: Math.max(0, cam.riskScore - 2)
      })));
      setSafetyScore(prev => ({
        ...prev,
        overall: Math.min(100, prev.overall + 0.5)
      }));
    }, 2000);
    return () => clearInterval(interval);
  }, []);

  // AI Report Generation
  const generateAIReport = async () => {
    const storedKey = localStorage.getItem('gemini_api_key');
    const apiKey = storedKey || process.env.API_KEY;

    if (!apiKey) {
      setReportContent("Critical Error: AI processing requires an Enterprise API Key.\nPlease go to 'Input Config' > 'AI Settings' to enter your key.");
      setIsReportOpen(true);
      return;
    }

    setIsReportOpen(true);
    setIsGeneratingReport(true);
    setReportContent("");

    try {
      const ai = new GoogleGenAI({ apiKey });
      const logData = detections.slice(0, 20).map(d => {
        const cam = cameras.find(c => c.id === d.cameraId);
        return `- Incident: ${d.description} (${d.severity}) | Camera: ${cam?.name || d.cameraId} | Location: ${cam?.location || 'Unknown'}`;
      }).join('\n');

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Generate a concise industrial safety shift report based on these incidents:\n${logData}`
      });

      if (!response.text) throw new Error("Empty response");
      setReportContent(response.text);
    } catch (error: any) {
      setReportContent(`Failed to generate report: ${error.message}`);
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const stats = useMemo(() => {
    const activeCameras = cameras.filter(c => c.active).length;
    const highRiskCameras = cameras.filter(c => c.riskScore > 50).length;
    const criticalDetections = detections.filter(d => d.severity === 'critical').length;
    return { activeCameras, highRiskCameras, criticalDetections };
  }, [cameras, detections]);

  // Helper to get detection styles
  const getDetectionStyles = (severity: string) => {
    switch (severity) {
      case 'critical':
        return {
          card: 'bg-rose-950/40 border-rose-500/50 text-rose-200 shadow-[0_0_15px_rgba(244,63,94,0.1)]',
          badge: 'bg-rose-500/20 text-rose-300 border-rose-500/30',
          indicator: 'bg-rose-500'
        };
      case 'high':
        return {
          card: 'bg-orange-950/40 border-orange-500/50 text-orange-200',
          badge: 'bg-orange-500/20 text-orange-300 border-orange-500/30',
          indicator: 'bg-orange-500'
        };
      case 'medium':
        return {
          card: 'bg-amber-950/30 border-amber-500/40 text-amber-200',
          badge: 'bg-amber-500/20 text-amber-300 border-amber-500/30',
          indicator: 'bg-amber-500'
        };
      case 'low':
        return {
          card: 'bg-blue-950/30 border-blue-500/40 text-blue-200',
          badge: 'bg-blue-500/20 text-blue-300 border-blue-500/30',
          indicator: 'bg-blue-500'
        };
      default:
        return {
          card: 'bg-slate-800 border-slate-700 text-slate-300',
          badge: 'bg-slate-700 text-slate-400 border-slate-600',
          indicator: 'bg-slate-600'
        };
    }
  };

  return (
    <AuthGuard>
      <div className="flex flex-col h-screen bg-slate-950 text-slate-200">
        <header className="flex-none h-16 border-b border-slate-800 bg-slate-900/50 backdrop-blur-md px-6 flex items-center justify-between z-10">
          <div className="flex items-center gap-4">
            <div className="bg-blue-600/20 p-2 rounded-lg border border-blue-500/30">
              <Shield className="w-6 h-6 text-blue-500" />
            </div>
            <div>
              <h1 className="text-xl font-bold text-white tracking-tight">HSE Guardian <span className="text-blue-500">AI</span></h1>
              <div className="flex items-center gap-2 text-xs text-slate-400">
                <span className={`flex items-center gap-1 ${
                  perfMetrics.status === 'critical' ? 'text-rose-500 font-bold' : 
                  perfMetrics.status === 'warning' ? 'text-amber-500' : 'text-emerald-500'
                }`}>
                  <Activity className="w-3 h-3" /> System Status
                </span>
                <span className="w-1 h-1 bg-slate-600 rounded-full"></span>
                <span>FPS: {perfMetrics.fps}</span>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-4">
             <button 
               onClick={() => setIsConfigOpen(true)}
               className="flex items-center gap-2 px-3 py-1.5 bg-slate-800 hover:bg-slate-700 text-slate-300 border border-slate-700 rounded-lg text-xs font-bold transition-colors"
             >
               <Settings2 className="w-4 h-4" />
               Input Config
             </button>
             <div className="h-8 w-px bg-slate-800"></div>
             <div className="flex flex-col items-end">
               <span className="text-xs text-slate-400 font-medium uppercase tracking-wider">Safety Score</span>
               <div className="flex items-baseline gap-1">
                 <span className={`text-2xl font-bold ${
                   safetyScore.overall >= 90 ? 'text-emerald-500' :
                   safetyScore.overall >= 70 ? 'text-amber-500' : 'text-rose-500'
                 }`}>{Math.floor(safetyScore.overall)}</span>
               </div>
             </div>
          </div>
        </header>

        <main className="flex-1 flex overflow-hidden">
          <div className="flex-1 flex flex-col min-w-0 bg-slate-950">
            <div className="flex-none h-14 border-b border-slate-800 flex items-center justify-between px-4">
               <div className="flex items-center gap-2">
                 <button
                   onClick={() => setViewMode(viewMode === 'grid' ? 'single' : 'grid')}
                   className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-lg transition-colors"
                   title="Toggle View"
                 >
                   {viewMode === 'grid' ? <Maximize2 className="w-5 h-5" /> : <Grid className="w-5 h-5" />}
                 </button>
                 <div className="h-6 w-px bg-slate-800 mx-2"></div>
                 <select
                   value={filterRisk}
                   onChange={(e) => setFilterRisk(e.target.value as any)}
                   className="bg-slate-900 border border-slate-700 text-sm rounded-lg px-3 py-1.5 focus:outline-none focus:border-blue-500 text-slate-300"
                 >
                   <option value="all">All Cameras</option>
                   <option value="high">High Risk Only</option>
                 </select>
               </div>

               <div className="flex items-center gap-3">
                 <Pagination
                   currentPage={currentPage}
                   totalPages={totalPages}
                   onPageChange={setCurrentPage}
                 />
                 <div className="flex gap-2 ml-4">
                   <button
                     onClick={startAllCamerasInPage}
                     className="flex items-center gap-2 px-3 py-1.5 bg-emerald-600/20 text-emerald-500 border border-emerald-600/30 hover:bg-emerald-600/30 rounded-lg text-sm font-medium transition-colors"
                   >
                     <Play className="w-4 h-4" /> Start Page
                   </button>
                   <button
                     onClick={stopAllCameras}
                     className="flex items-center gap-2 px-3 py-1.5 bg-rose-600/20 text-rose-500 border border-rose-600/30 hover:bg-rose-600/30 rounded-lg text-sm font-medium transition-colors"
                   >
                     <Pause className="w-4 h-4" /> Stop All
                   </button>
                 </div>
               </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 custom-scrollbar">
              {viewMode === 'grid' ? (
                <CameraGrid
                  cameras={cameras}
                  visibleCameras={visibleCameras}
                  onCameraSelect={handleCameraSelect}
                  selectedCamera={selectedCameraId}
                />
              ) : (
                <SingleCameraView 
                  camera={activeCamera} 
                  onBack={() => setViewMode('grid')}
                />
              )}
            </div>
          </div>

          <aside className="w-80 border-l border-slate-800 bg-slate-900 flex flex-col">
            <div className="p-4 border-b border-slate-800 flex justify-between items-center">
              <h2 className="text-sm font-bold text-slate-100 uppercase tracking-wider flex items-center gap-2">
                <AlertTriangle className="w-4 h-4 text-amber-500" />
                Live Alerts
              </h2>
              <button 
                onClick={generateAIReport}
                className="text-xs flex items-center gap-1 bg-blue-600 hover:bg-blue-500 text-white px-2 py-1 rounded transition-colors"
              >
                <FileText className="w-3 h-3" /> Report
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
              {detections.length === 0 ? (
                 <div className="flex flex-col items-center justify-center h-40 text-slate-600 space-y-2">
                   <CheckCircle2 className="w-8 h-8 opacity-50" />
                   <span className="text-sm">No Active Violations</span>
                 </div>
              ) : (
                detections.map(det => {
                  const cam = cameras.find(c => c.id === det.cameraId);
                  const styles = getDetectionStyles(det.severity);
                  return (
                    <div 
                      key={det.id} 
                      onClick={() => handleCameraSelect(det.cameraId)}
                      className={`p-3 rounded-lg border text-sm transition-all duration-300 relative overflow-hidden pl-4 cursor-pointer hover:ring-2 hover:ring-white/10 ${styles.card}`}
                    >
                      <div className={`absolute left-0 top-0 bottom-0 w-1 ${styles.indicator}`}></div>
                      <div className="flex justify-between items-start mb-1">
                        <span className="font-semibold">{det.description}</span>
                        <span className={`text-[10px] uppercase font-bold px-1.5 py-0.5 rounded border ${styles.badge}`}>
                          {det.severity}
                        </span>
                      </div>
                      <div className="flex justify-between items-start text-xs opacity-70 mt-2 border-t border-white/10 pt-2">
                        <div className="flex flex-col">
                          <span className="font-medium text-white/90">{cam?.name || det.cameraId}</span>
                          <span className="text-[10px] uppercase tracking-wide opacity-80">{cam?.location || 'Unknown'}</span>
                        </div>
                        <span className="whitespace-nowrap ml-2">{new Date(det.timestamp).toLocaleTimeString()}</span>
                      </div>
                    </div>
                  );
                })
              )}
            </div>
          </aside>
        </main>

        {/* Modals */}
        {isReportOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
            <div className="bg-slate-900 border border-slate-700 w-full max-w-2xl rounded-xl shadow-2xl flex flex-col max-h-[85vh]">
              <div className="flex items-center justify-between p-4 border-b border-slate-800">
                <h3 className="text-lg font-bold text-white flex items-center gap-2">
                  <FileText className="w-5 h-5 text-blue-500" />
                  AI Shift Incident Report
                </h3>
                <button onClick={() => setIsReportOpen(false)} className="text-slate-400 hover:text-white">
                  <X className="w-5 h-5" />
                </button>
              </div>
              <div className="flex-1 p-6 overflow-y-auto custom-scrollbar bg-slate-950/50 font-mono text-sm leading-relaxed">
                {isGeneratingReport ? (
                  <div className="flex flex-col items-center justify-center h-48 space-y-4">
                    <Loader2 className="w-8 h-8 text-blue-500 animate-spin" />
                    <p className="text-slate-400 animate-pulse text-center">Synthesizing Safety Data via Gemini...</p>
                  </div>
                ) : (
                  <div className="prose prose-invert max-w-none whitespace-pre-wrap">{reportContent}</div>
                )}
              </div>
            </div>
          </div>
        )}

        {isConfigOpen && (
          <CameraSetupModal
            cameras={cameras}
            onUpdateCameras={setCameras}
            onClose={() => setIsConfigOpen(false)}
          />
        )}

        <div className="hidden">
          {visibleCameras.map(cam => (
            <React.Fragment key={`proc-${cam.id}`}>
              <video
                ref={el => { if (el) videoRefs.current.set(cam.id, el); }}
                muted
                playsInline
                autoPlay
                width={CAMERA_WIDTH}
                height={CAMERA_HEIGHT}
              />
              <canvas
                ref={el => { if (el) canvasRefs.current.set(cam.id, el); }}
                width={CAMERA_WIDTH}
                height={CAMERA_HEIGHT}
              />
            </React.Fragment>
          ))}
        </div>
      </div>
    </AuthGuard>
  );
}

import React, { useState, useEffect } from 'react';
import { X, RefreshCw, HardDrive, Globe, Plus, Camera, Trash2, Key, Save, Check, ShieldAlert } from 'lucide-react';
import { CameraDevice } from '../types';

interface CameraSetupModalProps {
  cameras: CameraDevice[];
  onUpdateCameras: (cameras: CameraDevice[]) => void;
  onClose: () => void;
}

export const CameraSetupModal: React.FC<CameraSetupModalProps> = ({ cameras, onUpdateCameras, onClose }) => {
  const [activeTab, setActiveTab] = useState<'local' | 'network' | 'settings'>('local');
  const [availableDevices, setAvailableDevices] = useState<MediaDeviceInfo[]>([]);
  const [ipForm, setIpForm] = useState({ name: '', location: '', url: '' });

  // API Key State
  const [apiKey, setApiKey] = useState('');
  const [isKeySaved, setIsKeySaved] = useState(false);

  // Load initial data
  useEffect(() => {
    refreshDevices();
    const savedKey = localStorage.getItem('gemini_api_key');
    if (savedKey) setApiKey(savedKey);
  }, []);

  // Scan for local hardware
  const refreshDevices = async () => {
    if (!navigator.mediaDevices || !navigator.mediaDevices.enumerateDevices) {
      console.warn("Media Devices API not supported in this environment");
      return;
    }

    try {
      // 1. Enumerate first to see if any video devices exist
      let devices = await navigator.mediaDevices.enumerateDevices();
      const hasVideoInput = devices.some(d => d.kind === 'videoinput');

      // 2. Only request permissions if we detect video inputs
      // This prevents "Requested device not found" error when no camera exists
      if (hasVideoInput) {
        try {
          // Request permission to get labels
          const stream = await navigator.mediaDevices.getUserMedia({ video: true });
          // Stop stream immediately as we only needed permissions
          stream.getTracks().forEach(t => t.stop());

          // Re-enumerate to get devices with labels
          devices = await navigator.mediaDevices.enumerateDevices();
        } catch (permErr: any) {
          // Gracefully handle permission denial or device access errors
          console.warn("Camera permission denied or device inaccessible:", permErr.message);
        }
      }

      const videoInputs = devices.filter(d => d.kind === 'videoinput');
      setAvailableDevices(videoInputs);
    } catch (err) {
      console.warn("Error enumerating devices:", err);
    }
  };

  const addLocalDevice = (device: MediaDeviceInfo) => {
    const newCam: CameraDevice = {
      id: `local-${device.deviceId.substring(0, 8)}`,
      name: device.label || `USB Camera ${availableDevices.indexOf(device) + 1}`,
      location: 'Local Hardware',
      active: false,
      riskScore: 0,
      fps: 0,
      status: 'offline',
      connectionType: 'local',
      deviceId: device.deviceId
    };
    onUpdateCameras([newCam, ...cameras]);
  };

  const addIpCamera = () => {
    if (!ipForm.url) return;
    const newCam: CameraDevice = {
      id: `ip-${Date.now()}`,
      name: ipForm.name || 'IP Camera',
      location: ipForm.location || 'Remote',
      active: true, // Auto active for IP
      riskScore: 0,
      fps: 0,
      status: 'online',
      connectionType: 'network',
      streamUrl: ipForm.url
    };
    onUpdateCameras([newCam, ...cameras]);
    setIpForm({ name: '', location: '', url: '' });
  };

  const removeCamera = (id: string) => {
    onUpdateCameras(cameras.filter(c => c.id !== id));
  };

  const saveApiKey = () => {
    if (apiKey.trim()) {
      localStorage.setItem('gemini_api_key', apiKey.trim());
      setIsKeySaved(true);
      setTimeout(() => setIsKeySaved(false), 2000);
    } else {
      localStorage.removeItem('gemini_api_key');
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
      <div className="bg-slate-900 border border-slate-700 w-full max-w-4xl rounded-xl shadow-2xl flex flex-col max-h-[85vh]">
        <div className="flex items-center justify-between p-6 border-b border-slate-800">
          <div>
            <h3 className="text-xl font-bold text-white">System Configuration</h3>
            <p className="text-sm text-slate-400">Manage hardware inputs, networks, and AI settings</p>
          </div>
          <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors">
            <X className="w-6 h-6" />
          </button>
        </div>

        <div className="flex border-b border-slate-800">
          <button
            onClick={() => setActiveTab('local')}
            className={`flex-1 py-4 text-sm font-bold uppercase tracking-wider flex items-center justify-center gap-2 border-b-2 transition-colors ${
              activeTab === 'local' ? 'border-blue-500 text-blue-500 bg-blue-500/5' : 'border-transparent text-slate-500 hover:text-slate-300'
            }`}
          >
            <HardDrive className="w-4 h-4" /> Local Hardware
          </button>
          <button
            onClick={() => setActiveTab('network')}
            className={`flex-1 py-4 text-sm font-bold uppercase tracking-wider flex items-center justify-center gap-2 border-b-2 transition-colors ${
              activeTab === 'network' ? 'border-purple-500 text-purple-500 bg-purple-500/5' : 'border-transparent text-slate-500 hover:text-slate-300'
            }`}
          >
            <Globe className="w-4 h-4" /> Network / IP
          </button>
          <button
            onClick={() => setActiveTab('settings')}
            className={`flex-1 py-4 text-sm font-bold uppercase tracking-wider flex items-center justify-center gap-2 border-b-2 transition-colors ${
              activeTab === 'settings' ? 'border-amber-500 text-amber-500 bg-amber-500/5' : 'border-transparent text-slate-500 hover:text-slate-300'
            }`}
          >
            <Key className="w-4 h-4" /> AI Settings
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 bg-slate-950/50">
          {activeTab === 'local' && (
            <div className="space-y-6">
              <div className="flex justify-between items-center bg-slate-800/50 p-4 rounded-lg border border-slate-700">
                <div>
                  <h4 className="font-bold text-white">Available Video Inputs</h4>
                  <p className="text-xs text-slate-400">Scan for Webcams, Capture Cards, and HDMI Inputs</p>
                </div>
                <button 
                  onClick={refreshDevices}
                  className="px-4 py-2 bg-slate-700 hover:bg-slate-600 text-white rounded-lg text-xs font-bold flex items-center gap-2 transition-colors"
                >
                  <RefreshCw className="w-4 h-4" /> Rescan Hardware
                </button>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {availableDevices.map((device, idx) => (
                  <div key={device.deviceId} className="bg-slate-900 border border-slate-700 p-4 rounded-xl flex items-center justify-between group hover:border-blue-500/50 transition-colors">
                    <div className="flex items-center gap-3">
                      <div className="bg-slate-800 p-2 rounded-lg text-slate-400 group-hover:text-blue-400">
                        <Camera className="w-6 h-6" />
                      </div>
                      <div>
                        <div className="font-bold text-sm text-white truncate max-w-[200px]">{device.label || `Device ${idx + 1}`}</div>
                        <div className="text-[10px] text-slate-500 font-mono">{device.deviceId.substring(0, 12)}...</div>
                      </div>
                    </div>
                    {cameras.some(c => c.deviceId === device.deviceId) ? (
                      <span className="text-xs text-emerald-500 font-bold px-3 py-1 bg-emerald-500/10 rounded-full">ADDED</span>
                    ) : (
                      <button 
                        onClick={() => addLocalDevice(device)}
                        className="px-3 py-1.5 bg-blue-600 hover:bg-blue-500 text-white text-xs font-bold rounded-lg flex items-center gap-1"
                      >
                        <Plus className="w-3 h-3" /> Add
                      </button>
                    )}
                  </div>
                ))}
                {availableDevices.length === 0 && (
                  <div className="col-span-full py-8 text-center text-slate-500 bg-slate-900/50 border border-dashed border-slate-700 rounded-xl">
                    <p>No local camera devices found.</p>
                    <p className="text-xs mt-1">Check connections or use Network Streams.</p>
                  </div>
                )}
              </div>
            </div>
          )}

          {activeTab === 'network' && (
            <div className="space-y-6">
              <div className="bg-slate-800/50 p-6 rounded-xl border border-slate-700 space-y-4">
                <h4 className="font-bold text-white">Add IP Camera</h4>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <input
                    type="text"
                    placeholder="Camera Name (e.g., Gate 1)"
                    value={ipForm.name}
                    onChange={e => setIpForm({...ipForm, name: e.target.value})}
                    className="bg-slate-900 border border-slate-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:border-purple-500"
                  />
                  <input
                    type="text"
                    placeholder="Location"
                    value={ipForm.location}
                    onChange={e => setIpForm({...ipForm, location: e.target.value})}
                    className="bg-slate-900 border border-slate-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:border-purple-500"
                  />
                  <input
                    type="text"
                    placeholder="Stream URL (http://.../mjpeg)"
                    value={ipForm.url}
                    onChange={e => setIpForm({...ipForm, url: e.target.value})}
                    className="col-span-1 md:col-span-2 bg-slate-900 border border-slate-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:border-purple-500 font-mono text-sm"
                  />
                </div>
                <div className="flex justify-end">
                   <button 
                    onClick={addIpCamera}
                    disabled={!ipForm.url}
                    className="px-6 py-2 bg-purple-600 hover:bg-purple-500 disabled:opacity-50 disabled:cursor-not-allowed text-white font-bold rounded-lg flex items-center gap-2"
                   >
                     <Plus className="w-4 h-4" /> Add Stream
                   </button>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'settings' && (
            <div className="space-y-6">
              <div className="bg-slate-800/50 p-6 rounded-xl border border-slate-700 space-y-4">
                <div className="flex items-start gap-4">
                  <div className="bg-amber-500/10 p-3 rounded-xl">
                    <Key className="w-8 h-8 text-amber-500" />
                  </div>
                  <div className="flex-1">
                    <h4 className="font-bold text-white text-lg">Google Gemini API Configuration</h4>
                    <p className="text-slate-400 text-sm mt-1">
                      Enter your Gemini API key to enable AI reporting and analysis. This key will be stored locally in your browser.
                    </p>
                  </div>
                </div>

                <div className="mt-4">
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2">API Key</label>
                  <div className="flex gap-2">
                    <input
                      type="password"
                      placeholder="AIzaSy..."
                      value={apiKey}
                      onChange={(e) => setApiKey(e.target.value)}
                      className="flex-1 bg-slate-950 border border-slate-700 rounded-lg px-4 py-3 text-white font-mono focus:outline-none focus:border-amber-500 focus:ring-1 focus:ring-amber-500 transition-all"
                    />
                    <button
                      onClick={saveApiKey}
                      className={`px-6 rounded-lg font-bold flex items-center gap-2 transition-all ${
                        isKeySaved 
                          ? 'bg-emerald-600 text-white' 
                          : 'bg-amber-600 hover:bg-amber-500 text-white'
                      }`}
                    >
                      {isKeySaved ? <Check className="w-5 h-5" /> : <Save className="w-5 h-5" />}
                      {isKeySaved ? 'Saved' : 'Save Key'}
                    </button>
                  </div>
                </div>

                <div className="flex items-center gap-2 p-3 bg-blue-900/20 border border-blue-500/20 rounded-lg text-blue-300 text-xs mt-2">
                   <ShieldAlert className="w-4 h-4 flex-shrink-0" />
                   <p>Your API key is stored securely in LocalStorage. Clear your browser cache to remove it.</p>
                </div>
              </div>
            </div>
          )}

          {activeTab !== 'settings' && (
            <div className="mt-8">
              <h4 className="font-bold text-white mb-4">Configured Cameras ({cameras.length})</h4>
              <div className="grid grid-cols-1 gap-2">
                {cameras.map((cam, idx) => (
                  <div key={cam.id} className="flex items-center justify-between bg-slate-900 p-3 rounded-lg border border-slate-800">
                    <div className="flex items-center gap-3">
                      <span className="text-xs font-mono text-slate-600 w-6">{idx + 1}</span>
                      <div>
                        <div className="font-bold text-sm text-slate-200">{cam.name}</div>
                        <div className="text-xs text-slate-500 flex gap-2">
                          <span>{cam.location}</span>
                          <span className="text-slate-600">•</span>
                          <span className="uppercase">{cam.connectionType}</span>
                        </div>
                      </div>
                    </div>
                    <button 
                      onClick={() => removeCamera(cam.id)}
                      className="text-slate-500 hover:text-rose-500 p-2 transition-colors"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { Shield, Play, Pause, Grid, Maximize2, AlertTriangle, Activity, CheckCircle2, FileText, X, Loader2, Settings2 } from 'lucide-react';
import { GoogleGenAI } from "@google/genai";
import { CameraGrid } from './components/CameraGrid';
import { Pagination } from './components/Pagination';
import { SingleCameraView } from './components/SingleCameraView';
import { AuthGuard } from './components/AuthGuard';
import { CameraSetupModal } from './components/CameraSetupModal';
import { Detection, CameraDevice, SafetyScore } from './types';
import { performanceMonitor } from './utils/performanceMonitor';

// Constants
const MAX_LOGS = 100;
const FRAME_SKIP = 10;
const CAMERA_WIDTH = 320;
const CAMERA_HEIGHT = 240;
const MAX_SIMULTANEOUS_STREAMS = 9;
const CAMERAS_PER_PAGE = 9;

export default function HSEGuardianAI() {
  // State
  const [cameras, setCameras] = useState<CameraDevice[]>(() => 
    Array.from({ length: 9 }, (_, i) => ({
      id: `cam${i + 1}`,
      name: `Simulated Unit ${i + 1}`,
      location: `Zone ${Math.floor(i / 10) + 1} - Sec ${(i % 10) + 1}`,
      active: false,
      riskScore: 0,
      fps: 0,
      status: 'offline' as const,
      connectionType: 'simulation' as const
    }))
  );

  const [detections, setDetections] = useState<Detection[]>([]);
  const [safetyScore, setSafetyScore] = useState<SafetyScore>({
    overall: 98,
    ppe: 99,
    behavior: 95,
    environment: 98
  });

  const [selectedCameraId, setSelectedCameraId] = useState<string>('cam1');
  const [currentPage, setCurrentPage] = useState(0);
  const [viewMode, setViewMode] = useState<'grid' | 'single'>('grid');
  const [filterRisk, setFilterRisk] = useState<'all' | 'high'>('all');

  // Report State
  const [isReportOpen, setIsReportOpen] = useState(false);
  const [reportContent, setReportContent] = useState("");
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);

  // Config Modal State
  const [isConfigOpen, setIsConfigOpen] = useState(false);

  // Performance State
  const [perfMetrics, setPerfMetrics] = useState({ 
    fps: 0, 
    memory: 0, 
    status: 'healthy' as 'healthy' | 'warning' | 'critical' 
  });

  // Refs for processing
  const videoRefs = useRef<Map<string, HTMLVideoElement>>(new Map());
  const canvasRefs = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const frameCountRef = useRef(0);
  const processingQueueRef = useRef<string[]>([]);

  // Helpers
  const addDetection = useCallback((detection: Detection) => {
    setDetections(prev => {
      const updated = [detection, ...prev];
      return updated.slice(0, MAX_LOGS);
    });
  }, []);

  // Performance Monitor Integration
  useEffect(() => {
    performanceMonitor.start();

    const interval = setInterval(() => {
      const metrics = performanceMonitor.getCurrentMetrics();
      const health = performanceMonitor.getHealthStatus();

      if (metrics) {
        setPerfMetrics({
          fps: metrics.fps,
          memory: metrics.memoryUsage,
          status: health.status
        });
      }
    }, 1000);

    return () => {
      performanceMonitor.stop();
      clearInterval(interval);
    };
  }, []);

  // Pagination Logic
  const filteredCameras = useMemo(() => {
    if (filterRisk === 'all') return cameras;
    return cameras.filter(cam => cam.riskScore > 30);
  }, [cameras, filterRisk]);

  const totalPages = Math.ceil(filteredCameras.length / CAMERAS_PER_PAGE);

  const visibleCameras = useMemo(() => {
    const start = currentPage * CAMERAS_PER_PAGE;
    return filteredCameras.slice(start, start + CAMERAS_PER_PAGE);
  }, [filteredCameras, currentPage]);

  const activeCamera = useMemo(() => 
    cameras.find(c => c.id === selectedCameraId) || cameras[0]
  , [cameras, selectedCameraId]);

  // Update Processing Queue
  const updateProcessingQueue = useCallback(() => {
    const sorted = [...cameras]
      .filter(c => c.active)
      .sort((a, b) => b.riskScore - a.riskScore)
      .slice(0, MAX_SIMULTANEOUS_STREAMS)
      .map(c => c.id);

    processingQueueRef.current = sorted;
  }, [cameras]);

  useEffect(() => {
    updateProcessingQueue();
  }, [cameras, updateProcessingQueue]);

  // Camera Control
  const startCamera = useCallback(async (cameraId: string) => {
    try {
      const camera = cameras.find(c => c.id === cameraId);
      if (!camera) return;

      const activeCount = cameras.filter(c => c.active).length;
      if (activeCount >= MAX_SIMULTANEOUS_STREAMS) {
        return;
      }

      // Handle Network Camera (Mock activation)
      if (camera.connectionType === 'network') {
        setCameras(prev => prev.map(cam => 
            cam.id === cameraId ? { ...cam, active: true, status: 'online' } : cam
        ));
        return;
      }

      // Handle Local Hardware Camera
      const constraints: MediaStreamConstraints = {
        video: {
          width: { ideal: CAMERA_WIDTH },
          height: { ideal: CAMERA_HEIGHT },
          frameRate: { ideal: 15 },
          // CRITICAL FIX: If we have a specific deviceId, use it!
          deviceId: camera.deviceId ? { exact: camera.deviceId } : undefined
        }
      };

      const stream = await navigator.mediaDevices.getUserMedia(constraints);

      setCameras(prev => prev.map(cam => 
        cam.id === cameraId 
          ? { ...cam, active: true, stream, status: 'online' }
          : cam
      ));

      const video = videoRefs.current.get(cameraId);
      if (video) {
        video.srcObject = stream;
        video.play().catch(e => console.error("Play error", e));
      }
    } catch (error: any) {
      console.warn('Camera access failed:', error.name, error.message);

      const isNotFoundError = error.name === 'NotFoundError' || error.name === 'DevicesNotFoundError';
      const isOverconstrained = error.name === 'OverconstrainedError';

      setCameras(prev => prev.map(cam =>
        cam.id === cameraId ? { 
            ...cam, 
            status: (isNotFoundError || isOverconstrained) ? 'no-hardware' : 'offline', 
            active: false 
        } : cam
      ));
    }
  }, [cameras]);

  const stopCamera = useCallback((cameraId: string) => {
    setCameras(prev => prev.map(cam => {
      if (cam.id === cameraId && cam.stream) {
        cam.stream.getTracks().forEach(track => track.stop());
        return { ...cam, active: false, stream: undefined, status: 'offline' };
      }
      return cam;
    }));

    const video = videoRefs.current.get(cameraId);
    if (video) video.srcObject = null;
  }, []);

  const handleCameraSelect = (id: string) => {
    setSelectedCameraId(id);
    setViewMode('single');
  };

  const startAllCamerasInPage = useCallback(async () => {
    const promises = visibleCameras
      .filter(c => !c.active && c.status !== 'no-hardware')
      .slice(0, MAX_SIMULTANEOUS_STREAMS)
      .map(c => startCamera(c.id));

    await Promise.allSettled(promises);
  }, [visibleCameras, startCamera]);

  const stopAllCameras = useCallback(() => {
    cameras.filter(c => c.active).forEach(c => stopCamera(c.id));
  }, [cameras, stopCamera]);

  // AI Simulation Loop
  const processFrame = useCallback((cameraId: string) => {
    if (!processingQueueRef.current.includes(cameraId)) return;

    // Only process simulated frames for now as a demo
    const camera = cameras.find(c => c.id === cameraId);
    // Real processing would grab frame from canvas

    frameCountRef.current++;
    if (frameCountRef.current % FRAME_SKIP !== 0) return;

    // Low probability random detection simulation for demo purposes
    if (Math.random() > 0.995) { 
      const violations = [
        { desc: 'Missing Helmet', type: 'ppe', severity: 'medium' },
        { desc: 'Restricted Area', type: 'geofence', severity: 'high' },
        { desc: 'Fall Detected', type: 'fall', severity: 'critical' },
      ] as const;

      const violation = violations[Math.floor(Math.random() * violations.length)];

      const detection: Detection = {
        id: `${cameraId}-${Date.now()}`,
        type: violation.type as any,
        severity: violation.severity as any,
        description: violation.desc,
        timestamp: Date.now(),
        cameraId
      };

      addDetection(detection);

      setCameras(prev => prev.map(cam =>
        cam.id === cameraId
          ? { 
              ...cam, 
              riskScore: Math.min(100, cam.riskScore + (violation.severity === 'critical' ? 30 : 10)), 
              lastDetection: Date.now() 
            }
          : cam
      ));
    }
  }, [addDetection, cameras]);

  // Animation Loop
  useEffect(() => {
    let animationFrame: number;
    const loop = () => {
      processingQueueRef.current.forEach(cameraId => {
        processFrame(cameraId);
      });
      animationFrame = requestAnimationFrame(loop);
    };
    loop();
    return () => cancelAnimationFrame(animationFrame);
  }, [processFrame]);

  // Score Decay (Recovery)
  useEffect(() => {
    const interval = setInterval(() => {
      setCameras(prev => prev.map(cam => ({
        ...cam,
        riskScore: Math.max(0, cam.riskScore - 2)
      })));
      setSafetyScore(prev => ({
        ...prev,
        overall: Math.min(100, prev.overall + 0.5)
      }));
    }, 2000);
    return () => clearInterval(interval);
  }, []);

  // AI Report Generation
  const generateAIReport = async () => {
    const storedKey = localStorage.getItem('gemini_api_key');
    const apiKey = storedKey || process.env.API_KEY;

    if (!apiKey) {
      setReportContent("Critical Error: AI processing requires an Enterprise API Key.\nPlease go to 'Input Config' > 'AI Settings' to enter your key.");
      setIsReportOpen(true);
      return;
    }

    setIsReportOpen(true);
    setIsGeneratingReport(true);
    setReportContent("");

    try {
      const ai = new GoogleGenAI({ apiKey });
      const logData = detections.slice(0, 20).map(d => {
        const cam = cameras.find(c => c.id === d.cameraId);
        return `- Incident: ${d.description} (${d.severity}) | Camera: ${cam?.name || d.cameraId} | Location: ${cam?.location || 'Unknown'}`;
      }).join('\n');

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Generate a concise industrial safety shift report based on these incidents:\n${logData}`
      });

      if (!response.text) throw new Error("Empty response");
      setReportContent(response.text);
    } catch (error: any) {
      setReportContent(`Failed to generate report: ${error.message}`);
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const stats = useMemo(() => {
    const activeCameras = cameras.filter(c => c.active).length;
    const highRiskCameras = cameras.filter(c => c.riskScore > 50).length;
    const criticalDetections = detections.filter(d => d.severity === 'critical').length;
    return { activeCameras, highRiskCameras, criticalDetections };
  }, [cameras, detections]);

  // Helper to get detection styles
  const getDetectionStyles = (severity: string) => {
    switch (severity) {
      case 'critical':
        return {
          card: 'bg-rose-950/40 border-rose-500/50 text-rose-200 shadow-[0_0_15px_rgba(244,63,94,0.1)]',
          badge: 'bg-rose-500/20 text-rose-300 border-rose-500/30',
          indicator: 'bg-rose-500'
        };
      case 'high':
        return {
          card: 'bg-orange-950/40 border-orange-500/50 text-orange-200',
          badge: 'bg-orange-500/20 text-orange-300 border-orange-500/30',
          indicator: 'bg-orange-500'
        };
      case 'medium':
        return {
          card: 'bg-amber-950/30 border-amber-500/40 text-amber-200',
          badge: 'bg-amber-500/20 text-amber-300 border-amber-500/30',
          indicator: 'bg-amber-500'
        };
      case 'low':
        return {
          card: 'bg-blue-950/30 border-blue-500/40 text-blue-200',
          badge: 'bg-blue-500/20 text-blue-300 border-blue-500/30',
          indicator: 'bg-blue-500'
        };
      default:
        return {
          card: 'bg-slate-800 border-slate-700 text-slate-300',
          badge: 'bg-slate-700 text-slate-400 border-slate-600',
          indicator: 'bg-slate-600'
        };
    }
  };

  return (
    <AuthGuard>
      <div className="flex flex-col h-screen bg-slate-950 text-slate-200">
        <header className="flex-none h-16 border-b border-slate-800 bg-slate-900/50 backdrop-blur-md px-6 flex items-center justify-between z-10">
          <div className="flex items-center gap-4">
            <div className="bg-blue-600/20 p-2 rounded-lg border border-blue-500/30">
              <Shield className="w-6 h-6 text-blue-500" />
            </div>
            <div>
              <h1 className="text-xl font-bold text-white tracking-tight">HSE Guardian <span className="text-blue-500">AI</span></h1>
              <div className="flex items-center gap-2 text-xs text-slate-400">
                <span className={`flex items-center gap-1 ${
                  perfMetrics.status === 'critical' ? 'text-rose-500 font-bold' : 
                  perfMetrics.status === 'warning' ? 'text-amber-500' : 'text-emerald-500'
                }`}>
                  <Activity className="w-3 h-3" /> System Status
                </span>
                <span className="w-1 h-1 bg-slate-600 rounded-full"></span>
                <span>FPS: {perfMetrics.fps}</span>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-4">
             <button 
               onClick={() => setIsConfigOpen(true)}
               className="flex items-center gap-2 px-3 py-1.5 bg-slate-800 hover:bg-slate-700 text-slate-300 border border-slate-700 rounded-lg text-xs font-bold transition-colors"
             >
               <Settings2 className="w-4 h-4" />
               Input Config
             </button>
             <div className="h-8 w-px bg-slate-800"></div>
             <div className="flex flex-col items-end">
               <span className="text-xs text-slate-400 font-medium uppercase tracking-wider">Safety Score</span>
               <div className="flex items-baseline gap-1">
                 <span className={`text-2xl font-bold ${
                   safetyScore.overall >= 90 ? 'text-emerald-500' :
                   safetyScore.overall >= 70 ? 'text-amber-500' : 'text-rose-500'
                 }`}>{Math.floor(safetyScore.overall)}</span>
               </div>
             </div>
          </div>
        </header>

        <main className="flex-1 flex overflow-hidden">
          <div className="flex-1 flex flex-col min-w-0 bg-slate-950">
            <div className="flex-none h-14 border-b border-slate-800 flex items-center justify-between px-4">
               <div className="flex items-center gap-2">
                 <button
                   onClick={() => setViewMode(viewMode === 'grid' ? 'single' : 'grid')}
                   className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-lg transition-colors"
                   title="Toggle View"
                 >
                   {viewMode === 'grid' ? <Maximize2 className="w-5 h-5" /> : <Grid className="w-5 h-5" />}
                 </button>
                 <div className="h-6 w-px bg-slate-800 mx-2"></div>
                 <select
                   value={filterRisk}
                   onChange={(e) => setFilterRisk(e.target.value as any)}
                   className="bg-slate-900 border border-slate-700 text-sm rounded-lg px-3 py-1.5 focus:outline-none focus:border-blue-500 text-slate-300"
                 >
                   <option value="all">All Cameras</option>
                   <option value="high">High Risk Only</option>
                 </select>
               </div>

               <div className="flex items-center gap-3">
                 <Pagination
                   currentPage={currentPage}
                   totalPages={totalPages}
                   onPageChange={setCurrentPage}
                 />
                 <div className="flex gap-2 ml-4">
                   <button
                     onClick={startAllCamerasInPage}
                     className="flex items-center gap-2 px-3 py-1.5 bg-emerald-600/20 text-emerald-500 border border-emerald-600/30 hover:bg-emerald-600/30 rounded-lg text-sm font-medium transition-colors"
                   >
                     <Play className="w-4 h-4" /> Start Page
                   </button>
                   <button
                     onClick={stopAllCameras}
                     className="flex items-center gap-2 px-3 py-1.5 bg-rose-600/20 text-rose-500 border border-rose-600/30 hover:bg-rose-600/30 rounded-lg text-sm font-medium transition-colors"
                   >
                     <Pause className="w-4 h-4" /> Stop All
                   </button>
                 </div>
               </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 custom-scrollbar">
              {viewMode === 'grid' ? (
                <CameraGrid
                  cameras={cameras}
                  visibleCameras={visibleCameras}
                  onCameraSelect={handleCameraSelect}
                  selectedCamera={selectedCameraId}
                />
              ) : (
                <SingleCameraView 
                  camera={activeCamera} 
                  onBack={() => setViewMode('grid')}
                />
              )}
            </div>
          </div>

          <aside className="w-80 border-l border-slate-800 bg-slate-900 flex flex-col">
            <div className="p-4 border-b border-slate-800 flex justify-between items-center">
              <h2 className="text-sm font-bold text-slate-100 uppercase tracking-wider flex items-center gap-2">
                <AlertTriangle className="w-4 h-4 text-amber-500" />
                Live Alerts
              </h2>
              <button 
                onClick={generateAIReport}
                className="text-xs flex items-center gap-1 bg-blue-600 hover:bg-blue-500 text-white px-2 py-1 rounded transition-colors"
              >
                <FileText className="w-3 h-3" /> Report
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
              {detections.length === 0 ? (
                 <div className="flex flex-col items-center justify-center h-40 text-slate-600 space-y-2">
                   <CheckCircle2 className="w-8 h-8 opacity-50" />
                   <span className="text-sm">No Active Violations</span>
                 </div>
              ) : (
                detections.map(det => {
                  const cam = cameras.find(c => c.id === det.cameraId);
                  const styles = getDetectionStyles(det.severity);
                  return (
                    <div 
                      key={det.id} 
                      onClick={() => handleCameraSelect(det.cameraId)}
                      className={`p-3 rounded-lg border text-sm transition-all duration-300 relative overflow-hidden pl-4 cursor-pointer hover:ring-2 hover:ring-white/10 ${styles.card}`}
                    >
                      <div className={`absolute left-0 top-0 bottom-0 w-1 ${styles.indicator}`}></div>
                      <div className="flex justify-between items-start mb-1">
                        <span className="font-semibold">{det.description}</span>
                        <span className={`text-[10px] uppercase font-bold px-1.5 py-0.5 rounded border ${styles.badge}`}>
                          {det.severity}
                        </span>
                      </div>
                      <div className="flex justify-between items-start text-xs opacity-70 mt-2 border-t border-white/10 pt-2">
                        <div className="flex flex-col">
                          <span className="font-medium text-white/90">{cam?.name || det.cameraId}</span>
                          <span className="text-[10px] uppercase tracking-wide opacity-80">{cam?.location || 'Unknown'}</span>
                        </div>
                        <span className="whitespace-nowrap ml-2">{new Date(det.timestamp).toLocaleTimeString()}</span>
                      </div>
                    </div>
                  );
                })
              )}
            </div>
          </aside>
        </main>

        {/* Modals */}
        {isReportOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
            <div className="bg-slate-900 border border-slate-700 w-full max-w-2xl rounded-xl shadow-2xl flex flex-col max-h-[85vh]">
              <div className="flex items-center justify-between p-4 border-b border-slate-800">
                <h3 className="text-lg font-bold text-white flex items-center gap-2">
                  <FileText className="w-5 h-5 text-blue-500" />
                  AI Shift Incident Report
                </h3>
                <button onClick={() => setIsReportOpen(false)} className="text-slate-400 hover:text-white">
                  <X className="w-5 h-5" />
                </button>
              </div>
              <div className="flex-1 p-6 overflow-y-auto custom-scrollbar bg-slate-950/50 font-mono text-sm leading-relaxed">
                {isGeneratingReport ? (
                  <div className="flex flex-col items-center justify-center h-48 space-y-4">
                    <Loader2 className="w-8 h-8 text-blue-500 animate-spin" />
                    <p className="text-slate-400 animate-pulse text-center">Synthesizing Safety Data via Gemini...</p>
                  </div>
                ) : (
                  <div className="prose prose-invert max-w-none whitespace-pre-wrap">{reportContent}</div>
                )}
              </div>
            </div>
          </div>
        )}

        {isConfigOpen && (
          <CameraSetupModal
            cameras={cameras}
            onUpdateCameras={setCameras}
            onClose={() => setIsConfigOpen(false)}
          />
        )}

        <div className="hidden">
          {visibleCameras.map(cam => (
            <React.Fragment key={`proc-${cam.id}`}>
              <video
                ref={el => { if (el) videoRefs.current.set(cam.id, el); }}
                muted
                playsInline
                autoPlay
                width={CAMERA_WIDTH}
                height={CAMERA_HEIGHT}
              />
              <canvas
                ref={el => { if (el) canvasRefs.current.set(cam.id, el); }}
                width={CAMERA_WIDTH}
                height={CAMERA_HEIGHT}
              />
            </React.Fragment>
          ))}
        </div>
      </div>
    </AuthGuard>
  );
}

import React, { useEffect, useRef, memo } from 'react';

interface VideoPlayerProps {
  stream?: MediaStream;
  streamUrl?: string;
  className?: string;
}

export const VideoPlayer: React.FC<VideoPlayerProps> = memo(({ stream, streamUrl, className }) => {
  const videoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    if (videoRef.current && stream) {
      videoRef.current.srcObject = stream;
    }
  }, [stream]);

  // Handle Network Stream (MJPEG/Image source)
  if (streamUrl) {
    return (
      <img 
        src={streamUrl} 
        className={className} 
        alt="Live Stream"
        onError={(e) => {
          (e.target as HTMLImageElement).style.display = 'none';
        }} 
      />
    );
  }

  return (
    <video
      ref={videoRef}
      className={className}
      autoPlay
      muted
      playsInline
    />
  );
});

VideoPlayer.displayName = 'VideoPlayer';

import React, { memo } from 'react';
import { Camera, AlertTriangle, MonitorOff, Globe } from 'lucide-react';
import { CameraDevice } from '../types';
import { VideoPlayer } from './VideoPlayer';

interface CameraGridProps {
  cameras: CameraDevice[];
  visibleCameras: CameraDevice[];
  onCameraSelect: (id: string) => void;
  selectedCamera: string;
}

// Memoized Card Component to prevent re-rendering all grids when one camera updates
const CameraCard = memo(({ 
  cam, 
  isSelected, 
  onSelect 
}: { 
  cam: CameraDevice; 
  isSelected: boolean; 
  onSelect: (id: string) => void;
}) => {
  return (
    <div
      onClick={() => onSelect(cam.id)}
      className={`relative aspect-video bg-slate-900 rounded-xl overflow-hidden cursor-pointer transition-all duration-300 border-2 group ${
        isSelected ? 'border-blue-500 shadow-lg shadow-blue-500/20' : 'border-slate-800 hover:border-slate-600'
      } ${cam.riskScore > 50 ? 'animate-pulse-danger' : ''} ${cam.status === 'no-hardware' ? 'grayscale opacity-60' : ''}`}
    >
      {/* Video Preview */}
      <div className="absolute inset-0 flex items-center justify-center">
        {cam.connectionType === 'network' && cam.streamUrl ? (
           <div className="w-full h-full bg-black">
            <VideoPlayer streamUrl={cam.streamUrl} className="w-full h-full object-cover" />
          </div>
        ) : cam.active && cam.stream ? (
          <div className="w-full h-full bg-black">
            <VideoPlayer stream={cam.stream} className="w-full h-full object-cover" />
          </div>
        ) : cam.status === 'no-hardware' ? (
          <div className="flex flex-col items-center justify-center text-rose-500/50">
            <MonitorOff className="w-10 h-10 mb-2" />
            <span className="text-[10px] uppercase tracking-[0.2em] font-bold">No Hardware</span>
          </div>
        ) : (
          <div className="flex flex-col items-center justify-center text-slate-600 group-hover:text-slate-500 transition-colors">
            {cam.connectionType === 'network' ? <Globe className="w-10 h-10 mb-2" /> : <Camera className="w-10 h-10 mb-2" />}
            <span className="text-xs uppercase tracking-wider font-semibold">Offline</span>
          </div>
        )}
      </div>

      {/* Camera Info Overlay */}
      <div className="absolute bottom-0 left-0 right-0 bg-gradient-to-t from-black/90 via-black/60 to-transparent p-3 backdrop-blur-[2px]">
        <div className="flex items-center justify-between">
          <div className="flex-1 min-w-0">
            <p className="text-sm font-semibold text-white truncate shadow-black drop-shadow-md">{cam.name}</p>
            <p className="text-xs text-slate-300 truncate shadow-black drop-shadow-md">{cam.location}</p>
          </div>
          <div className="flex items-center gap-2">
            {cam.riskScore > 30 && (
              <span className="flex items-center gap-1 bg-red-500/20 text-red-400 px-1.5 py-0.5 rounded text-[10px] font-bold border border-red-500/30">
                RISK {cam.riskScore}
              </span>
            )}
            <div className={`w-2.5 h-2.5 rounded-full shadow-lg ${
              cam.status === 'online' ? 'bg-emerald-500 shadow-emerald-500/50' :
              cam.status === 'processing' ? 'bg-amber-500 animate-pulse' :
              cam.status === 'no-hardware' ? 'bg-slate-600' :
              'bg-rose-500'
            }`} />
          </div>
        </div>
      </div>

      {/* Risk Indicator */}
      {cam.riskScore > 70 && cam.status !== 'no-hardware' && (
        <div className="absolute top-2 right-2 bg-red-900/80 p-1.5 rounded-lg border border-red-500/50 backdrop-blur-sm animate-bounce">
          <AlertTriangle className="w-5 h-5 text-red-500" />
        </div>
      )}
    </div>
  );
});

CameraCard.displayName = 'CameraCard';

