import React, { useEffect, useRef, memo } from 'react';

interface VideoPlayerProps {
  stream?: MediaStream;
  streamUrl?: string;
  style?: React.CSSProperties;
}

export const VideoPlayer: React.FC<VideoPlayerProps> = memo(({ stream, streamUrl, style }) => {
  const videoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    if (videoRef.current && stream) {
      videoRef.current.srcObject = stream;
    }
  }, [stream]);

  const commonStyle: React.CSSProperties = {
    width: '100%',
    height: '100%',
    objectFit: 'cover',
    ...style
  };

  // Handle Network Stream (MJPEG/Image source)
  if (streamUrl) {
    return (
      <img 
        src={streamUrl} 
        alt="Live Stream"
        style={commonStyle}
        onError={(e) => {
          (e.target as HTMLImageElement).style.display = 'none';
        }} 
      />
    );
  }

  return (
    <video
      ref={videoRef}
      autoPlay
      muted
      playsInline
      style={commonStyle}
    />
  );
});

VideoPlayer.displayName = 'VideoPlayer';

import React from 'react';
import { ChevronLeft, ChevronRight } from './Icons';
import { theme } from '../theme';

interface PaginationProps {
  currentPage: number;
  totalPages: number;
  onPageChange: (page: number) => void;
}

export const Pagination: React.FC<PaginationProps> = ({
  currentPage,
  totalPages,
  onPageChange
}) => {
  const buttonStyle = (disabled: boolean) => ({
    padding: '6px',
    backgroundColor: theme.colors.border,
    color: theme.colors.textMuted,
    border: 'none',
    borderRadius: '4px',
    cursor: disabled ? 'not-allowed' : 'pointer',
    opacity: disabled ? 0.3 : 1,
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center'
  });

  return (
    <div style={{
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      gap: '8px',
      backgroundColor: 'rgba(15, 23, 42, 0.5)',
      padding: '4px',
      borderRadius: '8px',
      border: `1px solid ${theme.colors.border}`
    }}>
      <button
        onClick={() => onPageChange(Math.max(0, currentPage - 1))}
        disabled={currentPage === 0}
        style={buttonStyle(currentPage === 0)}
      >
        <ChevronLeft size={16} />
      </button>

      <span style={{
        fontSize: '12px',
        fontWeight: 500,
        color: theme.colors.textMuted,
        minWidth: '4rem',
        textAlign: 'center'
      }}>
        Page {currentPage + 1} / {totalPages}
      </span>

      <button
        onClick={() => onPageChange(Math.min(totalPages - 1, currentPage + 1))}
        disabled={currentPage === totalPages - 1}
        style={buttonStyle(currentPage === totalPages - 1)}
      >
        <ChevronRight size={16} />
      </button>
    </div>
  );
};

import React, { memo } from 'react';
import { Camera, AlertTriangle, MonitorOff, Globe } from './Icons';
import { CameraDevice } from '../types';
import { VideoPlayer } from './VideoPlayer';
import { theme } from '../theme';

interface CameraGridProps {
  cameras: CameraDevice[];
  visibleCameras: CameraDevice[];
  onCameraSelect: (id: string) => void;
  selectedCamera: string;
}

const CameraCard = memo(({ 
  cam, 
  isSelected, 
  onSelect 
}: { 
  cam: CameraDevice; 
  isSelected: boolean; 
  onSelect: (id: string) => void;
}) => {

  const cardStyle: React.CSSProperties = {
    position: 'relative',
    aspectRatio: '16/9',
    backgroundColor: theme.colors.panel,
    borderRadius: '12px',
    overflow: 'hidden',
    cursor: 'pointer',
    border: isSelected ? `2px solid ${theme.colors.primary}` : `2px solid ${theme.colors.border}`,
    boxShadow: isSelected ? `0 0 10px ${theme.colors.primary}33` : 'none',
    transition: 'all 0.3s ease',
    opacity: cam.status === 'no-hardware' ? 0.6 : 1,
    filter: cam.status === 'no-hardware' ? 'grayscale(100%)' : 'none',
    width: '100%',
    minWidth: '300px',
    flex: '1 1 300px',
  };

  const overlayStyle: React.CSSProperties = {
    position: 'absolute',
    inset: 0,
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    backgroundColor: '#000'
  };

  const infoOverlayStyle: React.CSSProperties = {
    position: 'absolute',
    bottom: 0, left: 0, right: 0,
    background: 'linear-gradient(to top, rgba(0,0,0,0.9), rgba(0,0,0,0.6), transparent)',
    padding: '12px',
    backdropFilter: 'blur(2px)',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center'
  };

  return (
    <div onClick={() => onSelect(cam.id)} style={cardStyle}>
      {/* Video Preview */}
      <div style={overlayStyle}>
        {cam.connectionType === 'network' && cam.streamUrl ? (
          <VideoPlayer streamUrl={cam.streamUrl} />
        ) : cam.active && cam.stream ? (
          <VideoPlayer stream={cam.stream} />
        ) : cam.status === 'no-hardware' ? (
          <div style={{...theme.layout.col, alignItems: 'center', color: theme.colors.danger, opacity: 0.5}}>
            <MonitorOff size={40} style={{marginBottom: 8}} />
            <span style={{fontSize: 10, fontWeight: 'bold', letterSpacing: '0.2em', textTransform: 'uppercase'}}>No Hardware</span>
          </div>
        ) : (
          <div style={{...theme.layout.col, alignItems: 'center', color: theme.colors.textMuted}}>
            {cam.connectionType === 'network' ? <Globe size={40} style={{marginBottom: 8}} /> : <Camera size={40} style={{marginBottom: 8}} />}
            <span style={{fontSize: 12, fontWeight: 600, letterSpacing: '0.1em', textTransform: 'uppercase'}}>Offline</span>
          </div>
        )}
      </div>

      {/* Camera Info Overlay */}
      <div style={infoOverlayStyle}>
        <div style={{ overflow: 'hidden' }}>
          <p style={{ fontSize: 14, fontWeight: 600, color: '#fff', margin: 0 }}>{cam.name}</p>
          <p style={{ fontSize: 12, color: theme.colors.textMuted, margin: 0 }}>{cam.location}</p>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          {cam.riskScore > 30 && (
            <span style={{
              display: 'flex', alignItems: 'center', gap: 4,
              backgroundColor: theme.colors.dangerBg,
              color: theme.colors.danger,
              padding: '2px 6px', borderRadius: 4, fontSize: 10, fontWeight: 'bold', border: `1px solid ${theme.colors.danger}44`
            }}>
              RISK {cam.riskScore}
            </span>
          )}
          <div style={{
            width: 10, height: 10, borderRadius: '50%',
            backgroundColor: cam.status === 'online' ? theme.colors.success : 
                           cam.status === 'processing' ? theme.colors.warning :
                           cam.status === 'no-hardware' ? theme.colors.textMuted : theme.colors.danger,
            boxShadow: cam.status === 'online' ? `0 0 10px ${theme.colors.success}` : 'none'
          }} />
        </div>
      </div>

      {/* Risk Indicator */}
      {cam.riskScore > 70 && cam.status !== 'no-hardware' && (
        <div style={{
          position: 'absolute', top: 8, right: 8,
          backgroundColor: 'rgba(127, 29, 29, 0.8)',
          padding: 6, borderRadius: 8,
          border: '1px solid rgba(239, 68, 68, 0.5)',
          backdropFilter: 'blur(4px)',
          animation: 'bounce 1s infinite'
        }}>
          <AlertTriangle size={20} color={theme.colors.danger} />
        </div>
      )}
    </div>
  );
});

CameraCard.displayName = 'CameraCard';

export const CameraGrid: React.FC<CameraGridProps> = ({
  visibleCameras,
  onCameraSelect,
  selectedCamera
}) => {
  return (
    <div style={{
      display: 'flex',
      flexWrap: 'wrap',
      gap: '12px',
      justifyContent: 'flex-start',
      width: '100%'
    }}>
      {visibleCameras.map(cam => (
        <CameraCard
          key={cam.id}
          cam={cam}
