interface SingleCameraViewProps {
  camera: CameraDevice;
  onBack: () => void;
  onAnalyze: (cameraId: string) => void;
}

export const SingleCameraView: React.FC<SingleCameraViewProps> = ({ camera, onBack, onAnalyze }) => {
  const [isFocusing, setIsFocusing] = useState(false);
  const [focusComplete, setFocusComplete] = useState(false);

  const performAutoFocus = useCallback(async () => {
    if (!camera.stream || camera.status !== 'online') return;

    setIsFocusing(true);
    setFocusComplete(false);

    // Hardware focus attempt
    const videoTrack = camera.stream.getVideoTracks()[0];
    if (videoTrack && typeof videoTrack.applyConstraints === 'function') {
      try {
        const capabilities = videoTrack.getCapabilities() as any;
        if (capabilities.focusMode && capabilities.focusMode.includes('continuous')) {
          await videoTrack.applyConstraints({
            advanced: [{ focusMode: 'continuous' }] as any
          });
        }
      } catch (err) {
        console.warn('Hardware focus adjustment not supported or failed:', err);
      }
    }

    // Visual focus simulation sequence
    setTimeout(() => {
      setIsFocusing(false);
      setFocusComplete(true);
      setTimeout(() => setFocusComplete(false), 2000);
    }, 1800);
  }, [camera.stream, camera.status]);

  useEffect(() => {
    if (camera.status === 'online') {
      performAutoFocus();
    }
  }, [camera.status, performAutoFocus]);

  const overlayHeaderStyle: React.CSSProperties = {
    position: 'absolute', top: 0, left: 0, right: 0, zIndex: 20,
    padding: '16px',
    background: 'linear-gradient(to bottom, rgba(0,0,0,0.8), transparent)',
    display: 'flex', justifyContent: 'space-between', alignItems: 'center'
  };

  const overlayFooterStyle: React.CSSProperties = {
    position: 'absolute', bottom: 0, left: 0, right: 0, zIndex: 20,
    padding: '24px',
    background: 'linear-gradient(to top, rgba(0,0,0,0.8), transparent)',
    display: 'flex', alignItems: 'flex-end', justifyContent: 'space-between',
    pointerEvents: 'none'
  };

  const btnStyle: React.CSSProperties = {
    padding: '8px',
    backgroundColor: 'rgba(30, 41, 59, 0.8)',
    border: '1px solid rgba(51, 65, 85, 0.5)',
    borderRadius: '8px',
    color: '#fff',
    cursor: 'pointer',
    display: 'flex', alignItems: 'center', justifyContent: 'center'
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100%', backgroundColor: '#000', position: 'relative', overflow: 'hidden' }}>

      {/* Top Header Overlay */}
      <div style={overlayHeaderStyle}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
          <button onClick={onBack} style={{ ...btnStyle, borderRadius: '50%' }}>
            <ChevronLeft size={20} />
          </button>
          <div>
            <h2 style={{ fontSize: 20, fontWeight: 'bold', color: '#fff', margin: 0, display: 'flex', alignItems: 'center', gap: 8 }}>
              {camera.name}
              <span style={{ fontSize: 12, fontFamily: 'monospace', backgroundColor: 'rgba(59, 130, 246, 0.2)', color: theme.colors.primaryLight, padding: '2px 8px', borderRadius: 4, border: '1px solid rgba(59, 130, 246, 0.3)', textTransform: 'uppercase' }}>Live</span>
            </h2>
            <p style={{ fontSize: 14, color: '#cbd5e1', textTransform: 'uppercase', letterSpacing: '0.1em', opacity: 0.8, margin: 0 }}>{camera.location}</p>
          </div>
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          {/* AI Deep Scan Button */}
          <button 
            onClick={() => onAnalyze(camera.id)}
            style={{ ...btnStyle, backgroundColor: theme.colors.info, borderColor: 'rgba(99, 102, 241, 0.5)', fontSize: 12, fontWeight: 'bold', textTransform: 'uppercase', gap: 8 }}
          >
            <Sparkles size={16} />
            <span>AI Deep Scan</span>
          </button>

          <button onClick={performAutoFocus} style={btnStyle}>
            <Target size={20} color={isFocusing ? theme.colors.primaryLight : '#fff'} />
          </button>
        </div>
      </div>

      {/* Main Video Area */}
      <div style={{ flex: 1, position: 'relative', display: 'flex', alignItems: 'center', justifyContent: 'center', width: '100%', height: '100%' }}>
        {camera.active && camera.stream ? (
          <VideoPlayer 
            stream={camera.stream} 
            style={{ 
              width: '100%', height: '100%', objectFit: 'contain',
              transition: 'all 0.7s',
              filter: isFocusing ? 'blur(2px)' : 'none',
              transform: isFocusing ? 'scale(1.01)' : 'scale(1)'
            }} 
          />
        ) : (
          <div style={{ ...theme.layout.col, alignItems: 'center', color: theme.colors.textMuted }}>
            <ShieldAlert size={80} style={{ opacity: 0.2, marginBottom: 16 }} />
            <p style={{ fontSize: 20, fontFamily: 'monospace', textTransform: 'uppercase', letterSpacing: '0.2em' }} className="animate-pulse">Establishing Secure Uplink...</p>
          </div>
        )}

        {/* AI Focus Overlay */}
        {isFocusing && (
          <div style={{ position: 'absolute', inset: 0, zIndex: 10, display: 'flex', alignItems: 'center', justifyContent: 'center', pointerEvents: 'none' }}>
            <div style={{ position: 'relative', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 8 }}>
               <Crosshair size={48} color={theme.colors.primaryLight} className="animate-spin" style={{opacity: 0.8}} />
               <span style={{ fontSize: 10, fontFamily: 'monospace', color: theme.colors.primaryLight, textTransform: 'uppercase', letterSpacing: '0.3em', fontWeight: 'bold', backgroundColor: 'rgba(0,0,0,0.4)', padding: '4px 8px', borderRadius: 4 }}>AI Auto-Focusing...</span>
            </div>
          </div>
        )}

        {/* Focus Complete */}
        {focusComplete && (
          <div style={{ position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%, -50%)', zIndex: 10, pointerEvents: 'none' }}>
            <div style={{ backgroundColor: theme.colors.successBg, border: `1px solid ${theme.colors.success}`, padding: '8px 16px', borderRadius: 999, display: 'flex', alignItems: 'center', gap: 8, backdropFilter: 'blur(4px)' }}>
              <Target size={16} color={theme.colors.success} />
              <span style={{ fontSize: 12, fontFamily: 'monospace', color: theme.colors.success, textTransform: 'uppercase', fontWeight: 'bold', letterSpacing: '0.1em' }}>Focus Calibrated</span>
            </div>
          </div>
        )}

        {/* Telemetry */}
        <div style={{ position: 'absolute', bottom: 24, left: 24, display: 'flex', flexDirection: 'column', gap: 8, fontFamily: 'monospace', fontSize: 10, color: 'rgba(16, 185, 129, 0.8)', pointerEvents: 'none' }}>
          <div style={{ display: 'flex', gap: 16 }}>
            <span>RES: 1920x1080</span>
            <span>FPS: {camera.active ? '24.2' : '0.0'}</span>
            <span>BR: 4.8Mbps</span>
          </div>
          <div style={{ display: 'flex', gap: 16 }}>
            <span>CODEC: H.264 High</span>
            <span>LATENCY: 42ms</span>
            <span>ENC: HARDWARE</span>
          </div>
        </div>

        {/* Risk Badge */}
        {camera.riskScore > 30 && (
          <div style={{ position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%, -50%)', pointerEvents: 'none' }}>
            <div style={{ 
              display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', 
              padding: 32, borderRadius: '50%', 
              border: `4px solid ${camera.riskScore > 70 ? 'rgba(225, 29, 72, 0.5)' : 'rgba(245, 158, 11, 0.5)'}`,
              backgroundColor: camera.riskScore > 70 ? 'rgba(225, 29, 72, 0.1)' : 'rgba(245, 158, 11, 0.1)',
              backdropFilter: 'blur(4px)'
            }} className="animate-pulse">
              <Activity size={48} color={camera.riskScore > 70 ? theme.colors.danger : theme.colors.warning} style={{ marginBottom: 8 }} />
              <span style={{ color: '#fff', fontWeight: 'bold', fontSize: 24 }}>RISK: {camera.riskScore}%</span>
            </div>
          </div>
        )}
      </div>

      {/* Footer Overlay */}
      <div style={overlayFooterStyle}>
        <div style={{ display: 'flex', gap: 32 }}>
           <div style={theme.layout.col}>
             <span style={{ fontSize: 12, color: theme.colors.textMuted, textTransform: 'uppercase', fontWeight: 'bold', marginBottom: 4 }}>Safety Index</span>
             <div style={{ height: 4, width: 128, backgroundColor: theme.colors.border, borderRadius: 999, overflow: 'hidden' }}>
               <div style={{ height: '100%', backgroundColor: theme.colors.primary, width: `${100 - camera.riskScore}%` }}></div>
             </div>
           </div>
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: 16, pointerEvents: 'auto' }}>
          <button style={{ ...btnStyle, fontSize: 12, fontWeight: 'bold', textTransform: 'uppercase', letterSpacing: '0.1em' }}>
            <Maximize size={16} style={{ marginRight: 8 }} /> Full Screen
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { X, RefreshCw, HardDrive, Globe, Plus, Camera, Trash2, Key, Save, Check, Cpu, Download, WifiOff } from './Icons';
import { CameraDevice, OfflineAIState } from '../types';
import { theme } from '../theme';

interface CameraSetupModalProps {
  cameras: CameraDevice[];
  onUpdateCameras: (cameras: CameraDevice[]) => void;
  onClose: () => void;
  offlineAI: OfflineAIState;
  onToggleOfflineAI: (enable: boolean) => void;
}

export const CameraSetupModal: React.FC<CameraSetupModalProps> = ({ 
  cameras, 
  onUpdateCameras, 
  onClose,
  offlineAI,
  onToggleOfflineAI
}) => {
  const [activeTab, setActiveTab] = useState<'local' | 'network' | 'settings'>('local');
  const [availableDevices, setAvailableDevices] = useState<MediaDeviceInfo[]>([]);
  const [ipForm, setIpForm] = useState({ name: '', location: '', url: '' });
  const [apiKey, setApiKey] = useState('');
  const [isKeySaved, setIsKeySaved] = useState(false);

  useEffect(() => {
    refreshDevices();
    const savedKey = localStorage.getItem('gemini_api_key');
    if (savedKey) setApiKey(savedKey);
  }, []);

  const refreshDevices = async () => {
    if (!navigator.mediaDevices || !navigator.mediaDevices.enumerateDevices) return;
    try {
      let devices = await navigator.mediaDevices.enumerateDevices();
      const hasVideoInput = devices.some(d => d.kind === 'videoinput');
      if (hasVideoInput && devices.some(d => d.label === '')) {
        try {
          const stream = await navigator.mediaDevices.getUserMedia({ video: true });
          stream.getTracks().forEach(t => t.stop());
          devices = await navigator.mediaDevices.enumerateDevices();
        } catch (e) { console.warn(e); }
      }
      setAvailableDevices(devices.filter(d => d.kind === 'videoinput'));
    } catch (err) { console.warn(err); }
  };

  const addLocalDevice = (device: MediaDeviceInfo) => {
    onUpdateCameras([{
      id: `local-${device.deviceId.substring(0, 8)}`,
      name: device.label || `USB Camera`,
      location: 'Local Hardware',
      active: false, riskScore: 0, fps: 0, status: 'offline', connectionType: 'local', deviceId: device.deviceId
    }, ...cameras]);
  };

  const addIpCamera = () => {
    if (!ipForm.url) return;
    onUpdateCameras([{
      id: `ip-${Date.now()}`,
      name: ipForm.name || 'IP Camera',
      location: ipForm.location || 'Remote',
      active: true, riskScore: 0, fps: 0, status: 'online', connectionType: 'network', streamUrl: ipForm.url
    }, ...cameras]);
    setIpForm({ name: '', location: '', url: '' });
  };

  const removeCamera = (id: string) => onUpdateCameras(cameras.filter(c => c.id !== id));

  const saveApiKey = () => {
    if (apiKey.trim()) {
      localStorage.setItem('gemini_api_key', apiKey.trim());
      setIsKeySaved(true);
      setTimeout(() => setIsKeySaved(false), 2000);
    } else localStorage.removeItem('gemini_api_key');
  };

  const inputStyle: React.CSSProperties = {
    backgroundColor: theme.colors.bg,
    border: `1px solid ${theme.colors.border}`,
    borderRadius: 8,
    padding: '8px 16px',
    color: '#fff',
    outline: 'none',
    width: '100%',
    marginBottom: 8
  };

  const buttonStyle = (primary = false) => ({
    padding: '8px 16px',
    borderRadius: 8,
    fontSize: 12, fontWeight: 'bold',
    backgroundColor: primary ? theme.colors.primary : theme.colors.border,
    color: '#fff',
    border: 'none',
    cursor: 'pointer',
    display: 'flex', alignItems: 'center', gap: 8
  });

  const tabStyle = (isActive: boolean) => ({
    flex: 1, padding: 16,
    border: 'none', borderBottom: `2px solid ${isActive ? theme.colors.primary : 'transparent'}`,
    backgroundColor: isActive ? 'rgba(37, 99, 235, 0.05)' : 'transparent',
    color: isActive ? theme.colors.primary : theme.colors.textMuted,
    fontWeight: 'bold', textTransform: 'uppercase' as const, fontSize: 14,
    cursor: 'pointer',
    display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8
  });

  return (
    <div style={{ position: 'fixed', inset: 0, zIndex: 50, display: 'flex', alignItems: 'center', justifyContent: 'center', backgroundColor: 'rgba(0,0,0,0.8)', backdropFilter: 'blur(4px)' }}>
      <div style={{ backgroundColor: theme.colors.panel, border: `1px solid ${theme.colors.border}`, width: '100%', maxWidth: 896, borderRadius: 12, display: 'flex', flexDirection: 'column', maxHeight: '85vh', boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.25)' }}>

        {/* Header */}
        <div style={{ ...theme.layout.flexBetween, padding: 24, borderBottom: `1px solid ${theme.colors.border}` }}>
          <div>
            <h3 style={{ fontSize: 20, fontWeight: 'bold', color: '#fff', margin: 0 }}>System Configuration</h3>
            <p style={{ fontSize: 14, color: theme.colors.textMuted, margin: '4px 0 0 0' }}>Manage hardware inputs, networks, and AI settings</p>
          </div>
          <button onClick={onClose} style={{ background: 'none', border: 'none', color: theme.colors.textMuted, cursor: 'pointer' }}><X size={24} /></button>
        </div>

        {/* Tabs */}
        <div style={{ display: 'flex', borderBottom: `1px solid ${theme.colors.border}` }}>
          <button onClick={() => setActiveTab('local')} style={tabStyle(activeTab === 'local')}><HardDrive size={16} /> Local Hardware</button>
          <button onClick={() => setActiveTab('network')} style={tabStyle(activeTab === 'network')}><Globe size={16} /> Network / IP</button>
          <button onClick={() => setActiveTab('settings')} style={tabStyle(activeTab === 'settings')}><Key size={16} /> AI Settings</button>
        </div>

        {/* Content */}
        <div style={{ flex: 1, overflowY: 'auto', padding: 24, backgroundColor: 'rgba(2, 6, 23, 0.5)' }}>
          {activeTab === 'local' && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>
              <div style={{ ...theme.layout.flexBetween, padding: 16, backgroundColor: 'rgba(30, 41, 59, 0.5)', borderRadius: 8, border: `1px solid ${theme.colors.border}` }}>
                <div><h4 style={{ margin: 0, fontWeight: 'bold' }}>Available Video Inputs</h4></div>
                <button onClick={refreshDevices} style={buttonStyle()}><RefreshCw size={16} /> Rescan</button>
              </div>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
                {availableDevices.map((device, idx) => (
                  <div key={device.deviceId} style={{ ...theme.layout.flexBetween, padding: 16, backgroundColor: theme.colors.panel, borderRadius: 12, border: `1px solid ${theme.colors.border}` }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                      <Camera size={24} color={theme.colors.textMuted} />
                      <div>
                        <div style={{ fontWeight: 'bold', fontSize: 14 }}>{device.label || `Device ${idx + 1}`}</div>
                        <div style={{ fontSize: 10, fontFamily: 'monospace', color: theme.colors.textMuted }}>{device.deviceId.substring(0, 12)}...</div>
                      </div>
                    </div>
                    <button onClick={() => addLocalDevice(device)} style={buttonStyle(true)}><Plus size={12} /> Add</button>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'network' && (
            <div style={{ padding: 24, backgroundColor: 'rgba(30, 41, 59, 0.5)', borderRadius: 12, border: `1px solid ${theme.colors.border}` }}>
               <h4 style={{ margin: '0 0 16px 0', fontWeight: 'bold' }}>Add IP Camera</h4>
               <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
                 <input type="text" placeholder="Name" value={ipForm.name} onChange={e => setIpForm({...ipForm, name: e.target.value})} style={inputStyle} />
                 <input type="text" placeholder="Location" value={ipForm.location} onChange={e => setIpForm({...ipForm, location: e.target.value})} style={inputStyle} />
                 <input type="text" placeholder="Stream URL" value={ipForm.url} onChange={e => setIpForm({...ipForm, url: e.target.value})} style={{...inputStyle, gridColumn: 'span 2', fontFamily: 'monospace'}} />
               </div>
               <div style={{ display: 'flex', justifyContent: 'flex-end', marginTop: 16 }}>
                 <button onClick={addIpCamera} style={{...buttonStyle(), backgroundColor: 'purple'}}><Plus size={16} /> Add Stream</button>
               </div>
            </div>
          )}

          {activeTab === 'settings' && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>
              {/* API Key */}
              <div style={{ padding: 24, backgroundColor: 'rgba(30, 41, 59, 0.5)', borderRadius: 12, border: `1px solid ${theme.colors.border}` }}>
                <h4 style={{ margin: '0 0 8px 0', fontWeight: 'bold' }}>Cloud AI (Gemini)</h4>
                <div style={{ display: 'flex', gap: 8 }}>
                  <input type="password" placeholder="AIzaSy..." value={apiKey} onChange={e => setApiKey(e.target.value)} style={{ ...inputStyle, marginBottom: 0 }} />
                  <button onClick={saveApiKey} style={{ ...buttonStyle(), backgroundColor: isKeySaved ? theme.colors.success : theme.colors.warning }}>
                    {isKeySaved ? <Check size={16} /> : <Save size={16} />} {isKeySaved ? 'Saved' : 'Save'}
                  </button>
                </div>
              </div>

              {/* Offline AI */}
              <div style={{ padding: 24, backgroundColor: 'rgba(30, 41, 59, 0.5)', borderRadius: 12, border: `1px solid ${theme.colors.border}` }}>
                 <div style={{ display: 'flex', gap: 16 }}>
                   <Cpu size={32} color={theme.colors.primary} />
                   <div style={{ flex: 1 }}>
                     <h4 style={{ margin: 0, fontWeight: 'bold' }}>Offline AI Core</h4>
                     <p style={{ margin: '4px 0', fontSize: 14, color: theme.colors.textMuted }}>Detects persons locally.</p>

                     <div style={{ ...theme.layout.flexBetween, marginTop: 16, padding: 16, backgroundColor: theme.colors.panel, borderRadius: 8 }}>
                       <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                         {offlineAI.isModelLoaded ? <WifiOff size={24} color={theme.colors.success} /> : <Download size={24} color={theme.colors.textMuted} />}
                         <div style={{ fontWeight: 'bold', fontSize: 14 }}>{offlineAI.isModelLoaded ? 'AI Core Active' : 'Model Not Loaded'}</div>
                       </div>
                       <button onClick={() => onToggleOfflineAI(!offlineAI.isModelLoaded)} style={buttonStyle(!offlineAI.isModelLoaded)}>
                         {offlineAI.isLoading ? 'Loading...' : offlineAI.isModelLoaded ? 'Unload Core' : 'Download Core'}
                       </button>
                     </div>
                   </div>
                 </div>
              </div>
            </div>
          )}

          {activeTab !== 'settings' && (
            <div style={{ marginTop: 32 }}>
              <h4 style={{ fontWeight: 'bold', marginBottom: 16 }}>Configured Cameras ({cameras.length})</h4>
              {cameras.map((cam, idx) => (
                <div key={cam.id} style={{ ...theme.layout.flexBetween, padding: 12, backgroundColor: theme.colors.panel, borderRadius: 8, marginBottom: 8, border: `1px solid ${theme.colors.border}` }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                    <span style={{ fontFamily: 'monospace', color: theme.colors.textMuted }}>{idx + 1}</span>
                    <div>
                      <div style={{ fontWeight: 'bold', fontSize: 14 }}>{cam.name}</div>
                      <div style={{ fontSize: 12, color: theme.colors.textMuted }}>{cam.location} • {cam.connectionType.toUpperCase()}</div>
                    </div>
                  </div>
                  <button onClick={() => removeCamera(cam.id)} style={{ background: 'none', border: 'none', color: theme.colors.textMuted, cursor: 'pointer' }}><Trash2 size={16} /></button>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Lock, Fingerprint, ShieldCheck, AlertCircle } from './Icons';
import { theme } from '../theme';

interface AuthGuardProps {
  children: React.ReactNode;
}

const INACTIVITY_TIMEOUT = 300000;
const MOCK_PIN = "1234";

export const AuthGuard: React.FC<AuthGuardProps> = ({ children }) => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [pin, setPin] = useState("");
  const [error, setError] = useState(false);
  const [isBiometricScanning, setIsBiometricScanning] = useState(false);
  const [lockedReason, setLockedReason] = useState<'initial' | 'timeout'>('initial');
  const inactivityTimerRef = useRef<number | undefined>(undefined);

  const lock = useCallback((reason: 'initial' | 'timeout' = 'timeout') => {
    setIsAuthenticated(false);
    setLockedReason(reason);
  }, []);

  const resetInactivityTimer = useCallback(() => {
    if (inactivityTimerRef.current !== undefined) window.clearTimeout(inactivityTimerRef.current);
    if (isAuthenticated) inactivityTimerRef.current = window.setTimeout(() => lock('timeout'), INACTIVITY_TIMEOUT);
  }, [isAuthenticated, lock]);

  const handlePinSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (pin === MOCK_PIN) unlock();
    else {
      setError(true);
      setPin("");
      setTimeout(() => setError(false), 2000);
    }
  };

  const unlock = useCallback(() => {
    setIsAuthenticated(true);
    setPin("");
    setError(false);
    resetInactivityTimer();
  }, [resetInactivityTimer]);

  const handleBiometricScan = () => {
    setIsBiometricScanning(true);
    setTimeout(() => { setIsBiometricScanning(false); unlock(); }, 1500);
  };

  useEffect(() => {
    const events = ['mousedown', 'keydown', 'scroll', 'touchstart'];
    const handleActivity = () => resetInactivityTimer();
    if (isAuthenticated) {
      events.forEach(event => window.addEventListener(event, handleActivity));
      resetInactivityTimer();
    }
    return () => {
      events.forEach(event => window.removeEventListener(event, handleActivity));
      if (inactivityTimerRef.current !== undefined) window.clearTimeout(inactivityTimerRef.current);
    };
  }, [isAuthenticated, resetInactivityTimer]);

  if (isAuthenticated) return <>{children}</>;

  return (
    <div style={{
      position: 'fixed', inset: 0, zIndex: 50,
      backgroundColor: theme.colors.bg,
      display: 'flex', alignItems: 'center', justifyContent: 'center', flexDirection: 'column',
      padding: 16
    }}>
      <div style={{
        width: '100%', maxWidth: 400,
        backgroundColor: theme.colors.panel,
        border: `1px solid ${theme.colors.border}`,
        borderRadius: 16,
        padding: 32,
        textAlign: 'center',
        position: 'relative',
        boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.5)'
      }}>
        <div style={{ marginBottom: 24, display: 'flex', justifyContent: 'center' }}>
          <div style={{ backgroundColor: theme.colors.border, width: 80, height: 80, borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            {lockedReason === 'timeout' ? <Lock size={40} color={theme.colors.warning} /> : <ShieldCheck size={40} color={theme.colors.primary} />}
          </div>
        </div>

        <h2 style={{ fontSize: 24, fontWeight: 'bold', color: '#fff', marginBottom: 8 }}>HSE Guardian Enterprise</h2>
        <p style={{ fontSize: 14, color: theme.colors.textMuted, marginBottom: 32 }}>
          {lockedReason === 'timeout' ? "Session timed out. Re-authenticate." : "Secure Terminal Access. Authorization Required."}
        </p>

        <form onSubmit={handlePinSubmit} style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
          <div>
            <input
              type="password" maxLength={4} value={pin} onChange={(e) => setPin(e.target.value)}
              placeholder="ENTER PIN" autoFocus
              style={{
                width: '100%', backgroundColor: theme.colors.bg,
                border: error ? `2px solid ${theme.colors.danger}` : `2px solid ${theme.colors.border}`,
                borderRadius: 8, padding: '12px 16px',
                textAlign: 'center', fontSize: 24, letterSpacing: '0.5em', fontFamily: 'monospace',
                color: '#fff', outline: 'none'
              }}
            />
            {error && <p style={{ color: theme.colors.danger, fontSize: 12, marginTop: 8, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 4 }}><AlertCircle size={12} /> INVALID CREDENTIALS</p>}
          </div>

          <button type="submit" style={{ width: '100%', backgroundColor: theme.colors.primary, color: '#fff', padding: 12, borderRadius: 8, border: 'none', fontWeight: 'bold', cursor: 'pointer' }}>
            UNLOCK TERMINAL
          </button>
        </form>

        <div style={{ marginTop: 32, paddingTop: 24, borderTop: `1px solid ${theme.colors.border}` }}>
          <button onClick={handleBiometricScan} disabled={isBiometricScanning} style={{ width: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8, background: 'none', border: 'none', color: theme.colors.textMuted, cursor: 'pointer' }}>
            <div style={{ padding: 8, borderRadius: '50%', backgroundColor: isBiometricScanning ? theme.colors.successBg : theme.colors.border, color: isBiometricScanning ? theme.colors.success : 'inherit' }}>
              <Fingerprint size={24} className={isBiometricScanning ? 'animate-pulse' : ''} />
            </div>
            <span style={{ fontSize: 14, fontWeight: 500 }}>{isBiometricScanning ? 'SCANNING...' : 'USE BIOMETRIC AUTH'}</span>
          </button>
        </div>
      </div>
      <div style={{ marginTop: 32, fontSize: 12, fontFamily: 'monospace', color: theme.colors.textMuted }}>SYSTEM ID: HSE-AI-8842 • TLS 1.3</div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { Shield, Play, Pause, Grid, Maximize2, AlertTriangle, Activity, CheckCircle2, FileText, X, Loader2, Settings2, WifiOff, Camera, Sparkles, ScanEye } from './components/Icons';
import { GoogleGenAI } from "@google/genai";
import * as tf from "@tensorflow/tfjs";
import * as cocoSsd from "@tensorflow-models/coco-ssd";

import { CameraGrid } from './components/CameraGrid';
import { Pagination } from './components/Pagination';
import { SingleCameraView } from './components/SingleCameraView';
import { AuthGuard } from './components/AuthGuard';
import { CameraSetupModal } from './components/CameraSetupModal';
import { Detection, CameraDevice, SafetyScore, OfflineAIState } from './types';
import { performanceMonitor } from './utils/performanceMonitor';
import { theme } from './theme';

// Constants
const MAX_LOGS = 100;
const FRAME_SKIP = 15;
const CAMERA_WIDTH = 320;
const CAMERA_HEIGHT = 240;
const CAMERAS_PER_PAGE = 9;

export default function HSEGuardianAI() {
  const [cameras, setCameras] = useState<CameraDevice[]>([]);
  const [detections, setDetections] = useState<Detection[]>([]);
  const [safetyScore, setSafetyScore] = useState<SafetyScore>({ overall: 100, ppe: 100, behavior: 100, environment: 100 });
  const [selectedCameraId, setSelectedCameraId] = useState<string | null>(null);
  const [currentPage, setCurrentPage] = useState(0);
  const [viewMode, setViewMode] = useState<'grid' | 'single'>('grid');
  const [filterRisk, setFilterRisk] = useState<'all' | 'high'>('all');

  const [isReportOpen, setIsReportOpen] = useState(false);
  const [reportContent, setReportContent] = useState("");
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);

  const [isVideoAnalysisOpen, setIsVideoAnalysisOpen] = useState(false);
  const [videoAnalysisContent, setVideoAnalysisContent] = useState("");
  const [isAnalyzingVideo, setIsAnalyzingVideo] = useState(false);

  const [isConfigOpen, setIsConfigOpen] = useState(false);

  const [offlineAI, setOfflineAI] = useState<OfflineAIState>({ isEnabled: false, isModelLoaded: false, isLoading: false, modelName: 'COCO-SSD Lite' });
  const [net, setNet] = useState<cocoSsd.ObjectDetection | null>(null);

  const [perfMetrics, setPerfMetrics] = useState({ fps: 0, memory: 0, status: 'healthy' as 'healthy' | 'warning' | 'critical' });

  const videoRefs = useRef<Map<string, HTMLVideoElement>>(new Map());
  const canvasRefs = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const frameCountRef = useRef(0);
  const lastAlertTimeRef = useRef<Record<string, number>>({});

  const addDetection = useCallback((detection: Detection) => {
    setDetections(prev => {
      const updated = [detection, ...prev];
      return updated.slice(0, MAX_LOGS);
    });
    setSafetyScore(prev => ({
        ...prev,
        overall: Math.max(0, prev.overall - 2),
        behavior: detection.type === 'behavior' ? Math.max(0, prev.behavior - 5) : prev.behavior,
        environment: detection.type === 'geofence' ? Math.max(0, prev.environment - 5) : prev.environment
    }));
  }, []);

  useEffect(() => {
    performanceMonitor.start();
    const interval = setInterval(() => {
      const metrics = performanceMonitor.getCurrentMetrics();
      const health = performanceMonitor.getHealthStatus();
      if (metrics) setPerfMetrics({ fps: metrics.fps, memory: metrics.memoryUsage, status: health.status });
    }, 1000);
    return () => { performanceMonitor.stop(); clearInterval(interval); };
  }, []);

  const filteredCameras = useMemo(() => filterRisk === 'all' ? cameras : cameras.filter(cam => cam.riskScore > 30), [cameras, filterRisk]);
  const totalPages = Math.max(1, Math.ceil(filteredCameras.length / CAMERAS_PER_PAGE));
  const visibleCameras = useMemo(() => filteredCameras.slice(currentPage * CAMERAS_PER_PAGE, currentPage * CAMERAS_PER_PAGE + CAMERAS_PER_PAGE), [filteredCameras, currentPage]);
  const activeCamera = useMemo(() => cameras.find(c => c.id === selectedCameraId) || cameras[0], [cameras, selectedCameraId]);

  const toggleOfflineAI = async (enable: boolean) => {
    if (enable) {
      setOfflineAI(prev => ({ ...prev, isLoading: true }));
      try {
        await tf.ready();
        const loadedNet = await cocoSsd.load({ base: 'lite_mobilenet_v2' });
        setNet(loadedNet);
        setOfflineAI(prev => ({ ...prev, isModelLoaded: true, isEnabled: true, isLoading: false }));
      } catch (err) {
        setOfflineAI(prev => ({ ...prev, isLoading: false }));
        alert("Failed to initialize AI Engine.");
      }
    } else {
      if (net) setNet(null);
      setOfflineAI(prev => ({ ...prev, isModelLoaded: false, isEnabled: false }));
    }
  };

  const startCamera = useCallback(async (cameraId: string) => {
    try {
      const camera = cameras.find(c => c.id === cameraId);
      if (!camera) return;
      if (camera.connectionType === 'network') {
        setCameras(prev => prev.map(cam => cam.id === cameraId ? { ...cam, active: true, status: 'online' } : cam));
        return;
      }
      const stream = await navigator.mediaDevices.getUserMedia({ video: { width: CAMERA_WIDTH, height: CAMERA_HEIGHT, frameRate: 15, deviceId: camera.deviceId ? { exact: camera.deviceId } : undefined } });
      setCameras(prev => prev.map(cam => cam.id === cameraId ? { ...cam, active: true, stream, status: 'online' } : cam));
      const video = videoRefs.current.get(cameraId);
      if (video) { video.srcObject = stream; video.play().catch(e => console.error(e)); }
    } catch (error) {
      setCameras(prev => prev.map(cam => cam.id === cameraId ? { ...cam, status: 'no-hardware', active: false } : cam));
    }
  }, [cameras]);

  const stopCamera = useCallback((cameraId: string) => {
    setCameras(prev => prev.map(cam => {
      if (cam.id === cameraId && cam.stream) { cam.stream.getTracks().forEach(track => track.stop()); return { ...cam, active: false, stream: undefined, status: 'offline' }; }
      return cam;
    }));
    const video = videoRefs.current.get(cameraId);
    if (video) video.srcObject = null;
  }, []);

  const handleCameraSelect = useCallback((id: string) => { setSelectedCameraId(id); setViewMode('single'); }, []);
  const startAllCamerasInPage = useCallback(async () => { visibleCameras.forEach(c => { if (!c.active && c.status !== 'no-hardware') startCamera(c.id); }); }, [visibleCameras, startCamera]);
  const stopAllCameras = useCallback(() => { cameras.filter(c => c.active).forEach(c => stopCamera(c.id)); }, [cameras, stopCamera]);

  const processFrame = useCallback(async () => {
    if (!offlineAI.isModelLoaded || !net) return;
    frameCountRef.current++;
    if (frameCountRef.current % FRAME_SKIP !== 0) return;

    let targetCameraId: string | null = null;
    if (viewMode === 'single' && selectedCameraId) {
        const cam = cameras.find(c => c.id === selectedCameraId);
        if (cam?.active) targetCameraId = selectedCameraId;
    } else {
        const activeOnPage = visibleCameras.find(c => c.active && c.status === 'online');
        if (activeOnPage) targetCameraId = activeOnPage.id;
    }
    if (!targetCameraId) return;

    const videoEl = videoRefs.current.get(targetCameraId);
    if (videoEl && videoEl.readyState === 4 && !videoEl.paused) {
        try {
            const predictions = await net.detect(videoEl);
            const now = Date.now();
            predictions.forEach(prediction => {
               if (prediction.score < 0.6) return;
               let detectionType: Detection['type'] | null = null;
               let description = '';
               let severity: Detection['severity'] = 'low';

               if (prediction.class === 'person') { detectionType = 'person'; description = 'Person Detected in Monitored Zone'; severity = 'medium'; } 
               else if (prediction.class === 'cell phone') { detectionType = 'behavior'; description = 'Safety Violation: Mobile Phone Usage'; severity = 'high'; }
               else if (['truck', 'car', 'bus', 'motorcycle'].includes(prediction.class)) { detectionType = 'geofence'; description = `Vehicle Detected (${prediction.class.toUpperCase()})`; severity = 'high'; }
               else if (['knife', 'scissors'].includes(prediction.class)) { detectionType = 'behavior'; description = `Sharp Object Detected`; severity = 'medium'; }

               if (detectionType) {
                  const cooldownKey = `${targetCameraId}-${detectionType}`;
                  if (now - (lastAlertTimeRef.current[cooldownKey] || 0) > 5000) {
                      lastAlertTimeRef.current[cooldownKey] = now;
                      addDetection({ id: `${targetCameraId}-${now}-${detectionType}`, type: detectionType, severity, description: `${description} (${Math.round(prediction.score * 100)}%)`, timestamp: now, cameraId: targetCameraId });
                      setCameras(prev => prev.map(cam => cam.id === targetCameraId ? { ...cam, riskScore: Math.min(100, cam.riskScore + 30), lastDetection: now } : cam));
                  }
               }
            });
        } catch (e) { console.warn(e); }
    }
  }, [addDetection, cameras, offlineAI.isModelLoaded, net, viewMode, selectedCameraId, visibleCameras]);

  useEffect(() => {
    let animationFrame: number;
    const loop = () => { processFrame(); animationFrame = requestAnimationFrame(loop); };
    loop();
    return () => cancelAnimationFrame(animationFrame);
  }, [processFrame]);

  useEffect(() => {
    const interval = setInterval(() => {
      setCameras(prev => prev.map(cam => ({ ...cam, riskScore: Math.max(0, cam.riskScore - 2) })));
      setSafetyScore(prev => ({ ...prev, overall: Math.min(100, prev.overall + 0.5), behavior: Math.min(100, prev.behavior + 0.5), environment: Math.min(100, prev.environment + 0.5) }));
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  const captureFrame = (cameraId: string): string | null => {
    const video = videoRefs.current.get(cameraId);
    if (video && video.readyState >= 2) {
       const canvas = document.createElement('canvas');
       canvas.width = video.videoWidth; canvas.height = video.videoHeight;
       const ctx = canvas.getContext('2d');
       if (ctx) { ctx.drawImage(video, 0, 0, canvas.width, canvas.height); return canvas.toDataURL('image/jpeg', 0.8).split(',')[1]; }
    }
    return null;
  };

  const performVideoAnalysis = async (cameraId: string) => {
    setIsVideoAnalysisOpen(true); setIsAnalyzingVideo(true); setVideoAnalysisContent("");
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const frames: string[] = [];
      for(let i=0; i<3; i++) {
          const f = captureFrame(cameraId); if(f) frames.push(f);
          await new Promise(r => setTimeout(r, 1000));
      }
      if (frames.length === 0) throw new Error("Could not capture video.");
      const parts: any[] = frames.map(f => ({ inlineData: { mimeType: 'image/jpeg', data: f } }));
      parts.push({ text: "Analyze this sequence. Describe activity and hazards." });
      const response = await ai.models.generateContent({ model: 'gemini-3-pro-preview', contents: { parts } });
      setVideoAnalysisContent(response.text || "No analysis generated.");
    } catch (error: any) { setVideoAnalysisContent(`Analysis Failed: ${error.message}`); } finally { setIsAnalyzingVideo(false); }
  };

  const generateAIReport = async () => {
    setIsReportOpen(true); setIsGeneratingReport(true); setReportContent("");
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const realDetections = detections.slice(0, 20);
      if (realDetections.length === 0) { setReportContent("No incidents."); setIsGeneratingReport(false); return; }
      const logData = realDetections.map(d => `- ${d.type}: ${d.description}`).join('\n');
      const response = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: `Safety Report from logs:\n${logData}` });
      setReportContent(response.text || "");
    } catch (error: any) { setReportContent(`Failed: ${error.message}`); } finally { setIsGeneratingReport(false); }
  };

  const getSeverityColor = (severity: string) => severity === 'critical' || severity === 'high' ? theme.colors.danger : severity === 'medium' ? theme.colors.warning : theme.colors.textMuted;

  return (
    <AuthGuard>
      <div style={{ display: 'flex', flexDirection: 'column', height: '100vh', backgroundColor: theme.colors.bg, color: theme.colors.text }}>
        {/* Header */}
        <header style={{ height: 64, borderBottom: `1px solid ${theme.colors.border}`, backgroundColor: 'rgba(15, 23, 42, 0.5)', backdropFilter: 'blur(12px)', padding: '0 24px', display: 'flex', alignItems: 'center', justifyContent: 'space-between', zIndex: 10 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
            <div style={{ backgroundColor: 'rgba(37, 99, 235, 0.2)', padding: 8, borderRadius: 8, border: `1px solid ${theme.colors.primaryLight}` }}>
              <Shield size={24} color={theme.colors.primary} />
            </div>
            <div>
              <h1 style={{ fontSize: 20, fontWeight: 'bold', margin: 0 }}>HSE Guardian <span style={{ color: theme.colors.primary }}>AI</span></h1>
              <div style={{ display: 'flex', alignItems: 'center', gap: 8, fontSize: 12, color: theme.colors.textMuted }}>
                <span style={{ display: 'flex', alignItems: 'center', gap: 4, color: perfMetrics.status === 'critical' ? theme.colors.danger : theme.colors.success }}>
                  <Activity size={12} /> {perfMetrics.status === 'healthy' ? 'System Optimized' : 'High Load'}
                </span>
                <span style={{ width: 4, height: 4, backgroundColor: theme.colors.textMuted, borderRadius: '50%' }}></span>
                <span>FPS: {perfMetrics.fps}</span>
                {offlineAI.isModelLoaded ? (
                   <span style={{ marginLeft: 8, display: 'flex', alignItems: 'center', gap: 4, color: theme.colors.success, backgroundColor: theme.colors.successBg, padding: '2px 6px', borderRadius: 4, border: `1px solid ${theme.colors.success}33` }}>
                     <WifiOff size={12} /> ENGINE ACTIVE
                   </span>
                ) : (
                    <span style={{ marginLeft: 8, display: 'flex', alignItems: 'center', gap: 4, color: theme.colors.danger, backgroundColor: theme.colors.dangerBg, padding: '2px 6px', borderRadius: 4, border: `1px solid ${theme.colors.danger}33` }}>
                     <WifiOff size={12} /> ENGINE STOPPED
                   </span>
                )}
              </div>
            </div>
          </div>

          <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
             <button onClick={() => setIsConfigOpen(true)} style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '6px 12px', backgroundColor: theme.colors.primary, color: '#fff', border: 'none', borderRadius: 8, fontSize: 12, fontWeight: 'bold', cursor: 'pointer' }}>
               <Settings2 size={16} /> System Setup
             </button>
             <div style={{ height: 32, width: 1, backgroundColor: theme.colors.border }}></div>
             <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end' }}>
               <span style={{ fontSize: 12, color: theme.colors.textMuted, fontWeight: 500, textTransform: 'uppercase' }}>Safety Score</span>
               <span style={{ fontSize: 24, fontWeight: 'bold', color: safetyScore.overall >= 90 ? theme.colors.success : theme.colors.warning }}>
                   {Math.floor(safetyScore.overall)}
               </span>
             </div>
          </div>
        </header>

        <main style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
          <div style={{ flex: 1, display: 'flex', flexDirection: 'column', minWidth: 0, backgroundColor: theme.colors.bg }}>
            {/* Toolbar */}
            <div style={{ height: 56, borderBottom: `1px solid ${theme.colors.border}`, display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '0 16px' }}>
               <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                 <button onClick={() => setViewMode(viewMode === 'grid' ? 'single' : 'grid')} disabled={cameras.length === 0} style={{ padding: 8, background: 'none', border: 'none', color: theme.colors.textMuted, cursor: 'pointer' }}>
                   {viewMode === 'grid' ? <Maximize2 size={20} /> : <Grid size={20} />}
                 </button>
               </div>

               <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                 <Pagination currentPage={currentPage} totalPages={totalPages} onPageChange={setCurrentPage} />
                 <div style={{ display: 'flex', gap: 8, marginLeft: 16 }}>
                   <button onClick={startAllCamerasInPage} disabled={cameras.length === 0} style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '6px 12px', backgroundColor: theme.colors.successBg, color: theme.colors.success, border: `1px solid ${theme.colors.success}44`, borderRadius: 8, fontSize: 14, fontWeight: 500, cursor: 'pointer' }}>
                     <Play size={16} /> Start Active
                   </button>
                   <button onClick={stopAllCameras} disabled={cameras.length === 0} style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '6px 12px', backgroundColor: theme.colors.dangerBg, color: theme.colors.danger, border: `1px solid ${theme.colors.danger}44`, borderRadius: 8, fontSize: 14, fontWeight: 500, cursor: 'pointer' }}>
                     <Pause size={16} /> Stop All
                   </button>
                 </div>
               </div>
            </div>

            <div style={{ flex: 1, overflowY: 'auto', padding: 16, position: 'relative' }} className="custom-scrollbar">
              {cameras.length === 0 ? (
                  <div style={{ position: 'absolute', inset: 0, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', color: theme.colors.textMuted, opacity: 0.6 }}>
                      <Camera size={80} style={{ marginBottom: 16 }} />
                      <h3 style={{ fontSize: 24, fontWeight: 'bold', color: '#cbd5e1', margin: 0 }}>No Cameras Configured</h3>
                      <p style={{ marginBottom: 24 }}>Please add hardware or network streams.</p>
                      <button onClick={() => setIsConfigOpen(true)} style={{ padding: '8px 24px', backgroundColor: theme.colors.border, color: '#fff', borderRadius: 999, fontWeight: 'bold', border: `1px solid ${theme.colors.textMuted}`, cursor: 'pointer' }}>
                          Open Configuration
                      </button>
                  </div>
              ) : viewMode === 'grid' ? (
                <CameraGrid cameras={cameras} visibleCameras={visibleCameras} onCameraSelect={handleCameraSelect} selectedCamera={selectedCameraId || ''} />
              ) : activeCamera ? (
                <SingleCameraView camera={activeCamera} onBack={() => setViewMode('grid')} onAnalyze={performVideoAnalysis} />
              ) : null}
            </div>
          </div>

          {/* Sidebar */}
          <aside style={{ width: 320, borderLeft: `1px solid ${theme.colors.border}`, backgroundColor: theme.colors.panel, display: 'flex', flexDirection: 'column' }}>
            <div style={{ padding: 16, borderBottom: `1px solid ${theme.colors.border}`, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <h2 style={{ fontSize: 14, fontWeight: 'bold', color: '#f1f5f9', textTransform: 'uppercase', letterSpacing: '0.05em', display: 'flex', alignItems: 'center', gap: 8, margin: 0 }}>
                <AlertTriangle size={16} color={theme.colors.warning} /> Live Detections
              </h2>
              <button onClick={generateAIReport} style={{ fontSize: 12, display: 'flex', alignItems: 'center', gap: 4, backgroundColor: theme.colors.border, color: '#fff', padding: '4px 8px', borderRadius: 4, border: 'none', cursor: 'pointer' }}>
                <FileText size={12} /> Log
              </button>
            </div>

            <div style={{ flex: 1, overflowY: 'auto', padding: 16, display: 'flex', flexDirection: 'column', gap: 12 }} className="custom-scrollbar">
              {!offlineAI.isModelLoaded ? (
                  <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: 160, color: theme.colors.textMuted, textAlign: 'center', padding: 16, border: `1px dashed ${theme.colors.border}`, borderRadius: 8, backgroundColor: 'rgba(15, 23, 42, 0.5)' }}>
                     <WifiOff size={32} style={{ marginBottom: 8, opacity: 0.5 }} />
                     <span style={{ fontWeight: 'bold', fontSize: 14 }}>AI Engine Offline</span>
                  </div>
              ) : detections.length === 0 ? (
                 <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: 160, color: theme.colors.textMuted, gap: 8 }}>
                   <CheckCircle2 size={32} style={{ opacity: 0.5 }} />
                   <span style={{ fontSize: 14 }}>Zone Clear</span>
                 </div>
              ) : (
                detections.map(det => {
                  const severityColor = getSeverityColor(det.severity);
                  return (
                    <div key={det.id} onClick={() => handleCameraSelect(det.cameraId)} style={{ padding: 12, borderRadius: 8, border: `1px solid ${theme.colors.border}`, backgroundColor: 'rgba(30, 41, 59, 0.3)', borderLeft: `4px solid ${severityColor}`, cursor: 'pointer' }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
                        <span style={{ fontWeight: 600, fontSize: 14 }}>{det.description}</span>
                        <span style={{ fontSize: 10, fontWeight: 'bold', textTransform: 'uppercase', padding: '2px 6px', borderRadius: 4, backgroundColor: severityColor, color: '#fff' }}>{det.type}</span>
                      </div>
                      <div style={{ fontSize: 12, opacity: 0.6, display: 'flex', justifyContent: 'space-between' }}>
                        <span>Cam: {cameras.find(c => c.id === det.cameraId)?.name}</span>
                        <span>{new Date(det.timestamp).toLocaleTimeString()}</span>
                      </div>
                    </div>
                  );
                })
              )}
            </div>
          </aside>
        </main>

        {/* Modals */}
        {isReportOpen && (
          <div style={{ position: 'fixed', inset: 0, zIndex: 50, display: 'flex', alignItems: 'center', justifyContent: 'center', backgroundColor: 'rgba(0,0,0,0.8)', backdropFilter: 'blur(4px)' }}>
            <div style={{ backgroundColor: theme.colors.panel, border: `1px solid ${theme.colors.border}`, width: '100%', maxWidth: 600, borderRadius: 12, display: 'flex', flexDirection: 'column', maxHeight: '85vh', boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.5)' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', padding: 16, borderBottom: `1px solid ${theme.colors.border}` }}>
                <h3 style={{ margin: 0, fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: 8 }}><FileText size={20} color={theme.colors.primary} /> Incident Report</h3>
                <button onClick={() => setIsReportOpen(false)} style={{ background: 'none', border: 'none', color: '#fff', cursor: 'pointer' }}><X size={20} /></button>
              </div>
              <div style={{ padding: 24, overflowY: 'auto', flex: 1, fontFamily: 'monospace', fontSize: 14, lineHeight: 1.5, whiteSpace: 'pre-wrap' }}>
                {isGeneratingReport ? <div style={{ textAlign: 'center', padding: 32 }}><Loader2 size={32} color={theme.colors.primary} className="animate-spin" /></div> : reportContent}
              </div>
            </div>
          </div>
        )}

        {isVideoAnalysisOpen && (
          <div style={{ position: 'fixed', inset: 0, zIndex: 50, display: 'flex', alignItems: 'center', justifyContent: 'center', backgroundColor: 'rgba(0,0,0,0.8)', backdropFilter: 'blur(4px)' }}>
            <div style={{ backgroundColor: theme.colors.panel, border: `1px solid ${theme.colors.border}`, width: '100%', maxWidth: 600, borderRadius: 12, display: 'flex', flexDirection: 'column', maxHeight: '85vh' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', padding: 16, borderBottom: `1px solid ${theme.colors.border}`, backgroundColor: 'rgba(99, 102, 241, 0.1)' }}>
                <h3 style={{ margin: 0, fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: 8 }}><ScanEye size={20} color={theme.colors.info} /> Video Analysis</h3>
                <button onClick={() => setIsVideoAnalysisOpen(false)} style={{ background: 'none', border: 'none', color: '#fff', cursor: 'pointer' }}><X size={20} /></button>
              </div>
              <div style={{ padding: 24, overflowY: 'auto', flex: 1, fontFamily: 'monospace', fontSize: 14, lineHeight: 1.5, whiteSpace: 'pre-wrap' }}>
                {isAnalyzingVideo ? <div style={{ textAlign: 'center', padding: 32 }}><Sparkles size={32} color={theme.colors.info} className="animate-pulse" /><p>Analyzing...</p></div> : videoAnalysisContent}
              </div>
            </div>
          </div>
        )}

        {isConfigOpen && <CameraSetupModal cameras={cameras} onUpdateCameras={setCameras} onClose={() => setIsConfigOpen(false)} offlineAI={offlineAI} onToggleOfflineAI={toggleOfflineAI} />}

        <div style={{ display: 'none' }}>
          {cameras.map(cam => <video key={`proc-${cam.id}`} ref={el => { if (el) videoRefs.current.set(cam.id, el); }} muted playsInline autoPlay width={CAMERA_WIDTH} height={CAMERA_HEIGHT} crossOrigin="anonymous" />)}
        </div>
      </div>
    </AuthGuard>
  );
}

import React, { memo } from 'react';
import { Camera, AlertTriangle, MonitorOff, Globe, Loader2, WifiOff } from './Icons';
